INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('稻瘟病', '稻热病,火烧瘟,颈瘟,节瘟,谷瘟', '病害', '水稻三大病害之一，可致减产30%以上甚至绝收。', '叶片初现褐色小斑点，后扩大为梭形病斑，中央灰白色，边缘褐色，有黄色晕圈；穗颈发病致枯白穗；节部变黑易折断；谷粒呈灰褐色椭圆形病斑，颖壳易破裂。急性型病斑暗绿，密生灰霉，慢性型典型梭形，有同心轮纹。', '高温高湿（25-30℃，湿度>90%）易发病；品种抗性差异大；氮肥过多、田间郁闭、长期深水灌溉加重发病；分蘖期、孕穗期、抽穗期为易感阶段；气流、雨水、昆虫传播孢子。', '选用抗病品种如\'汕优63\'、\'金优207\'；合理密植，科学施肥（氮磷钾平衡）；浅水勤灌，适时晒田；清除病残体，减少菌源；种子处理用1%石灰水浸种或咪鲜胺浸种；发病初期及时拔除病株。', '75%三环唑可湿性粉剂40-60克/亩喷雾；40%稻瘟灵乳油100毫升/亩喷雾；20%三环唑·硫磺悬浮剂60毫升/亩喷雾；25%吡唑醚菌酯乳剂20毫升/亩喷雾；2%春雷霉素水剂75-100毫升/亩喷雾，发病初期用药，间隔7-10天一次，连用2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('水稻纹枯病', '云纹病,烂脚瘟', '病害', '水稻纹枯病是由立枯丝核菌引起的一种真菌性病害。', '主要危害水稻叶鞘和叶片，初期在近水面叶鞘上产生暗绿色水渍状小斑点，后扩大为椭圆形云纹状病斑，边缘褐色，中央灰白色。病斑可相互融合形成不规则大斑，叶片枯黄下垂。严重时病菌侵入茎秆，导致植株倒伏，结实率下降，秕粒增多。湿度大时病斑表面产生灰白色蛛丝状菌丝，后期形成褐色菌核。', '高温高湿是发病的主要条件，适温25-32℃，相对湿度90%以上。病菌以菌核在土壤或病残体中越冬，通过水流、农事操作传播。长期深水灌溉、氮肥过量、密植、通风不良的田块发病重。分蘖盛期至抽穗期是发病高峰，雨季或连续阴雨天气易暴发流行。', '1. 选用抗病品种，如汕优63、Ⅱ优838等；2. 合理密植，科学施肥，避免氮肥过量，增施磷钾肥；3. 浅水勤灌，适时烤田，降低田间湿度；4. 及时清除病残体，减少菌源；5. 加强田间管理，改善通风透光条件。', '1. 井冈霉素：每亩用5%水剂150-200毫升，对水60-75公斤喷雾，间隔7-10天一次；2. 苯醚甲环唑：每亩用10%水分散粒剂20-30克，对水喷雾；3. 噻呋酰胺：每亩用24%悬浮剂15-20毫升，对水喷雾；4. 丙环唑：每亩用25%乳油10毫升，对水喷雾；5. 烯唑醇：每亩用12.5%可湿性粉剂30-40克，对水喷雾。发病初期开始用药，交替使用效果更佳。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('水稻白叶枯病', '水稻细菌性条斑病,水稻白叶瘟', '病害', '细菌性病害，致叶片枯萎，影响产量和品质。', '初期叶片水渍状病斑，灰绿色，后扩展为灰白色条斑，边缘波纹状。病部菌脓干燥后呈鱼籽状小颗粒。严重时全叶枯死，植株枯黄。苗期至抽穗期均可发病，以孕穗期最重。叶片枯死后，茎秆仍可存活，但籽粒不饱满。', '高温高湿（25-30℃，湿度80%以上）易发病。台风、暴雨后发病加重。种子带菌、病残体、灌溉水是主要初侵染源。伤口（如虫咬、机械损伤）利于病菌侵入。连作田、氮肥过量田发病重。', '选用抗病品种，种子消毒（用浸种灵或强氯精）。合理密植，科学施肥（增施磷钾肥，控氮）。浅水勤灌，避免深水淹苗。及时清除病株残体，减少菌源。台风暴雨后及时排水，喷药保护。', '20%噻唑锌悬浮剂，每亩100毫升兑水喷雾，间隔7天一次。20%叶枯唑可湿性粉剂，每亩100克兑水喷雾，发病初期使用。2%春雷霉素水剂，每亩100毫升兑水喷雾，安全间隔期21天。30%噻菌酯悬浮剂，每亩30毫升兑水喷雾，持效期长。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('稻飞虱', '稻褐虱,白背飞虱,灰飞虱', '虫害', '吸食水稻汁液，导致植株枯萎倒伏，严重时减产绝收。', '成虫和若虫群集在水稻基部吸食汁液，叶片出现黄白色斑点，逐渐枯黄。植株生长缓慢，分蘖减少，根系腐烂。严重时整株枯死，形成“穿顶”或“倒伏”，田间可见大量蜜露和煤污病。', '喜温暖高湿环境，适温20-30℃，湿度80%以上。每年发生3-4代，成虫有趋光性和趋绿性。台风或暴雨后易爆发，长期单一用药易产生抗药性。', '选用抗虫品种，合理密植，加强田间水肥管理。及时清除田边杂草，减少虫源。设置诱虫灯或黄板诱杀成虫。避免过量施用氮肥，增强植株抗性。', '1. 吡虫啉：每亩用20%可湿性粉剂30克，兑水喷雾。2. 噻嗪酮：25%可湿性粉剂50克/亩，喷雾防治若虫。3. 烯啶虫胺：10%水剂20毫升/亩，均匀喷雾。4. 氟啶虫胺腈：50%水分散粒剂10克/亩，持效期长。5. 毒死蜱：40%乳油50毫升/亩，注意安全间隔期。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('二化螟', '钻心虫,蛀秆虫,稻螟', '虫害', '钻蛀水稻茎秆，造成枯心、白穗，严重影响产量。', '幼虫蛀食水稻茎秆，导致分蘖期出现枯心苗，孕穗期形成白穗，受害植株叶片发黄，茎秆易折断。蛀孔处有虫粪排出，被害株内部可见隧道和虫体。严重时整株枯死，田间出现明显枯心团或白穗簇。', '喜温暖湿润环境，最适温度22-28℃，相对湿度80%以上。一年发生2-4代，以幼虫在稻桩或杂草中越冬。成虫趋光性强，多在夜间产卵于叶片上。雨季或田间积水多时发生加重。', '1. 选用抗虫品种；2. 及时清除田间稻桩和杂草，减少越冬虫源；3. 合理施肥，避免氮肥过量；4. 适时晒田，降低田间湿度；5. 人工摘除枯心团和白穗；6. 安装频振式杀虫灯诱杀成虫。', '1. 20%氯虫苯甲酰胺悬浮剂，每亩10-15毫升，兑水喷雾；2. 40%辛硫磷乳油，每亩100毫升，拌细土撒施；3. 1%甲氨基阿维菌素苯甲酸盐乳油，每亩30-40毫升，喷雾；4. 5%甲维盐水分散粒剂，每亩10克，兑水喷雾；5. 20%阿维·氟酰胺悬浮剂，每亩15毫升，喷雾。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('三化螟', '钻心虫,水稻螟虫', '虫害', '钻蛀水稻茎秆，造成枯心、白穗的毁灭性害虫。', '幼虫蛀入水稻茎秆内，取食内部组织，导致受害植株叶片卷缩、失绿，逐渐枯死，形成枯心苗；孕穗期受害则造成白穗，抽穗困难；灌浆期受害则出现虫伤株，籽粒不饱满，易倒伏。茎秆蛀孔处常有黄色蛀屑和虫粪排出。', '喜温暖潮湿环境，年均温20-30℃、相对湿度80%以上利于繁殖。一年发生2-4代，以老熟幼虫在稻桩或杂草中越冬。成虫具趋光性，多在夜间活动，卵多产于叶面中脉附近。分蘖期和孕穗期为危害高峰期。', '1. 农业防治：清除田边杂草，减少虫源；合理轮作，避免连作；深翻土壤，消灭越冬虫源。2. 生物防治：保护天敌如赤眼蜂、蜘蛛等；使用Bt制剂。3. 物理防治：安装频振式杀虫灯诱杀成虫。4. 化学防治：抓住卵孵化盛期和低龄幼虫期施药。', '1. 20%氯虫苯甲酰胺悬浮剂，每亩10-15毫升，兑水喷雾。2. 40%毒死蜱乳油，每亩50-75毫升，兑水喷雾。3. 1.8%阿维菌素乳油，每亩30-50毫升，兑水喷雾。4. 25%噻嗪酮可湿性粉剂，每亩40-60克，兑水喷雾。5. 20%甲维盐水分散粒剂，每亩10-15克，兑水喷雾。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('稻纵卷叶螟', '稻苞虫,卷叶虫', '虫害', '水稻主要食叶害虫，幼虫卷叶危害，影响光合作用', '幼虫将叶片卷成筒状，藏身其中取食叶肉，仅留表皮呈白色条斑，严重时全叶枯白。受害植株生长受阻，分蘖减少，千粒重下降，导致减产10%-30%。虫粪可见于卷叶内，田间可见白色透明膜状茧。', '喜温暖高湿环境，适温22-28℃，相对湿度80%以上。成虫有趋光性和趋绿性，卵多产于嫩叶上。每年发生2-8代，南方世代重叠明显。暴风雨可降低虫口密度，干旱则抑制繁殖。', '1.农业防治：合理密植，科学水肥管理，避免偏施氮肥；2.生物防治：保护天敌（蜘蛛、寄生蜂等），释放赤眼蜂；3.物理防治：安装频振式杀虫灯；4.化学防治：掌握防治适期，在低龄幼虫高峰期用药；5.抗虫品种：选用抗虫品种如\'两优培九\'。', '1.甲维盐：每亩用10毫升兑水30公斤喷雾，持效期7-10天；2.氯虫苯甲酰胺：每亩20毫升兑水喷雾，对高龄幼虫效果好；3.茚虫威：每亩15毫升均匀喷雾，速效性好；4.阿维菌素：每亩30毫升兑水喷雾，兼具杀卵作用；5.苏云金杆菌：每亩100克兑水喷雾，生物安全环保。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('水稻条纹叶枯病', '水稻条纹叶枯病,水稻条纹叶枯病,水稻条纹叶枯病', '病害', '水稻条纹叶枯病是由灰飞虱传播的水稻病毒病。', '发病初期，心叶沿叶脉出现黄白色条纹，后扩展至全叶，叶片卷曲、枯死。病株矮化，分蘖减少，穗小粒秕。后期病叶坏死，呈灰白色，易折断。根系发育不良，植株生长停滞。病株在田间呈点片分布，严重时全田枯死。', '灰飞虱是主要传播媒介，病毒在灰飞虱体内越冬。春季气温回升，灰飞虱活动频繁，传毒机会增加。水稻感病期与灰飞虱发生期吻合时发病重。高温干旱或低温多雨均有利于病害发生。品种间抗病性差异显著，感病品种易大面积流行。', '选用抗病品种，如\'宁粳1号\'、\'武运粳7号\'等。调整播期，避开灰飞虱迁飞高峰。清除田间及周边杂草，减少虫源。合理施肥，增强植株抗病性。采用防虫网覆盖育秧，防止灰飞虱传毒。', '可用10%吡虫啉可湿性粉剂20克/亩喷雾，防治灰飞虱；20%病毒A可湿性粉剂50克/亩喷雾，抑制病毒复制；1.5%植病灵乳剂100毫升/亩喷雾，增强植株抗性；2%宁南霉素水剂200毫升/亩喷雾，抑制病毒扩展；25%噻嗪酮可湿性粉剂30克/亩喷雾，杀灭若虫。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('水稻恶苗病', '恶苗病,徒长病', '病害', '水稻系统性真菌病害，导致植株徒长、枯死', '病株显著高于健株，节间 elongated，叶色淡黄，根系发育不良。后期病株基部产生粉红色霉层（分生孢子及孢子囊），叶片自下而上逐渐枯死。抽穗后病穗颖壳张开，不结实或结实不良，病节上产生黑色小点（子囊壳）。病株早衰，易倒伏，无经济价值。', '病原物为藤仓赤霉菌（Fusarium fujikuroi），主要通过带菌种子和土壤传播。高温高湿（25-35℃）利于发病，育秧期低温寡照、秧苗徒长时发病加重。伤口侵入是主要途径，种子带菌率是发病关键因素。', '1. 选用抗病品种和无病种子；2. 种子处理：用25%咪鲜胺乳油2000倍液或50%多菌灵可湿性粉剂500倍液浸种48小时；3. 加强栽培管理：合理密植，平衡施肥，适时晒田，降低田间湿度；4. 及时拔除病株并集中销毁，减少菌源。', '1. 25%咪鲜胺乳油2000倍液浸种48小时；2. 30%苯醚甲环唑·丙环唑乳油3000倍液喷雾，发病初期施用；3. 75%百菌清可湿性粉剂600倍液喷雾，间隔7天一次，连续2-3次；4. 50%多菌灵可湿性粉剂500倍液灌根，防治苗期病害。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('稻蝗', '中华稻蝗,东亚飞蝗,水稻蝗虫', '虫害', '主要啃食水稻叶片和茎秆，造成减产甚至绝收。', '稻蝗成虫和若虫啃食水稻叶片，形成缺刻或孔洞，严重时叶片仅剩叶脉；取食茎秆导致折断；低龄若虫群集危害，高龄分散；受害植株生长受阻，分蘖减少，穗小粒瘪，产量显著下降。', '稻蝗喜温暖湿润环境，夏季高温多雨时繁殖迅速；田间杂草多、管理粗放的地块发生重；单季稻、双季稻混种区虫口密度高；长期连作且缺乏轮作的地块易爆发。', '1. 农业防治：清除田边杂草，减少虫源；合理密植，改善通风；2. 生物防治：保护天敌如鸟类、青蛙、蜘蛛等；3. 物理防治：利用灯光诱杀成虫；4. 化学防治：在低龄若虫期及时喷药防治。', '1. 10%吡虫啉可湿性粉剂，每亩20-30克兑水喷雾；2. 5%高效氯氟氰菊酯乳油，每亩30-40毫升稀释喷雾；3. 48%毒死蜱乳油，每亩50-60毫升兑水均匀喷洒；4. 20%氯虫苯甲酰胺悬浮剂，每亩10-15毫升喷雾；5. 25%噻嗪酮可湿性粉剂，每亩30-40克兑水喷雾。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('水稻胡麻斑病', '水稻胡麻叶枯病,水稻芝麻斑病', '病害', '水稻真菌性病害，叶片出现褐色芝麻状病斑。', '叶片初生褐色小点，后扩大为椭圆形至梭形病斑，中央灰褐色至灰白色，边缘褐色，有黄色晕圈，病斑背面产生黑色霉层（分生孢子梗和分生孢子）。严重时病斑融合成大斑，叶片枯死。穗颈受害可导致穗枯，谷粒上形成褐色斑点，米粒变褐、变轻，影响产量和品质。', '病原为半知菌亚门长蠕孢属真菌，以分生孢子和菌丝体在病残体和种子上越冬。高温高湿（25-28℃，相对湿度80%以上）易发病，氮肥过多、植株徒长、长期深水灌溉或干旱后遇雨均会加重病情。稻瘟病流行年份常伴随胡麻斑病发生。', '1. 选用抗病品种，如湘晚籼12号、金优458等。2. 加强栽培管理：合理施肥，增施磷钾肥，避免偏施氮肥；科学灌溉，保持田间湿润，避免长期深水或干旱。3. 及时清除病残体，减少初侵染源。4. 种子处理：用50%多菌灵可湿性粉剂500倍液浸种24小时。5. 发病初期及时喷药保护，封锁发病中心。', '1. 75%百菌清可湿性粉剂：每亩用100-150克，兑水50-60公斤喷雾，间隔7-10天一次，连续2-3次。2. 50%多菌灵可湿性粉剂：每亩用100克，兑水50公斤喷雾，发病初期使用。3. 25%咪鲜胺乳油：每亩用40-50毫升，兑水50公斤喷雾，重点喷洒叶片正反面。4. 70%甲基硫菌灵可湿性粉剂：每亩用100-150克，兑水50公斤喷雾，交替使用以延缓抗性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('水稻细菌性条斑病', '稻白叶枯病,水稻条斑病', '病害', '水稻细菌性条斑病，由白叶枯病菌引起，导致叶片条状枯死。', '初期叶片出现水渍状小斑点，迅速扩展为灰白色至黄褐色条斑，边缘明显，病斑上可见黄色菌脓。严重时叶片枯萎，植株矮化，籽粒不实。病斑多沿叶脉扩展，呈长条状，湿度大时菌脓明显，干燥后呈颗粒状。叶鞘发病后出现类似症状，但病斑较短。', '高温高湿条件利于发病，气温25-30℃、相对湿度80%以上时病情发展迅速。台风、暴雨后易爆发，伤口增多利于病菌侵入。病原菌主要通过种子、病残体和流水传播，连作田、氮肥过量、田间积水发病加重。', '选用抗病品种，建立无病种子田。种子用40%叶枯唑浸种。合理施肥，避免偏施氮肥，增施磷钾肥。浅水勤灌，适时晒田，降低田间湿度。及时清除病残体，减少菌源。台风暴雨后及时喷药保护。', '推荐使用20%噻唑锌悬浮剂1000倍液喷雾，或30%噻菌酯悬浮剂1500倍液，每7天一次，连续2-3次。也可选用72%农用链霉素可溶性粉剂3000倍液，或50%氯溴异氰尿酸可溶性粉剂1000倍液，交替使用效果更佳。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('小麦锈病', '黄疸病,黄锈病,黑锈病', '病害', '小麦锈病是一种由真菌引起的严重病害，影响小麦产量和品质。', '小麦锈病主要表现为叶片、叶鞘和茎秆上出现黄色、橙色或红褐色的条状或点状孢子堆。条锈病呈鲜黄色，叶锈病呈橙黄色，秆锈病呈红褐色。孢子堆破裂后散出黄褐色粉末（夏孢子），严重时叶片枯黄，植株早衰，籽粒灌浆不足，导致产量显著下降。', '小麦锈病在温暖湿润的环境下易发生，条锈病适宜温度10-20℃，叶锈病15-25℃，秆锈病较高温度20-25℃。多雨、露水重或田间湿度大时发病严重。病菌通过气流传播，孢子萌发需要叶面有水膜。品种抗性差异大，感病品种在适宜条件下易爆发流行。', '选用抗病品种是关键，如郑麦9023、济麦22等。合理密植，避免田间郁闭；平衡施肥，增施磷钾肥，提高植株抗性；及时清除病残体，减少初侵染源；发病初期喷施保护性药剂，封锁发病中心。合理灌溉，避免田间长时间积水，降低湿度。', '推荐使用三唑酮（15%可湿性粉剂，每亩50-70克，喷雾）、戊唑醇（25%乳油，每亩30-40毫升，喷雾）、烯唑醇（12.5%可湿性粉剂，每亩30-40克，喷雾）、苯醚甲环唑（10%水分散粒剂，每亩30-40克，喷雾）、氟环唑（12.5%悬浮剂，每亩30-40毫升，喷雾）。发病初期用药，间隔7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('小麦赤霉病', '麦穗枯,烂穗病', '病害', '小麦穗部真菌病害，导致减产和毒素污染。', '初发病时在小穗颖壳上出现水渍状褐色小斑点，后扩展至整个小穗，呈枯黄色。湿度大时病部产生粉红色霉层（分生孢子及孢子座）。后期病部产生黑色小颗粒（子囊壳）。严重时整穗枯死，籽粒皱缩、灰白，丧失发芽力。病株茎节处也可出现褐色病斑。', '多雨潮湿气候是发病关键因素，尤其在小麦抽穗至灌浆期遇连续阴雨或多雾天气。病原菌（禾谷镰刀菌）通过风雨传播，从花器或伤口侵入。品种抗性差异显著，感病品种在适宜条件下发病重。田间病残体多、地势低洼、排水不良田块发病较重。', '选用抗病品种，如济麦22、郑麦366等。实行轮作，避免连作。深耕翻压病残体，减少初侵染源。合理施肥，避免偏施氮肥，增强植株抗性。抽穗期遇雨及时喷药保护，雨后补喷。收获后及时清理田间病残，减少越冬菌源。', '推荐药剂：① 50%多菌灵可湿性粉剂，每亩用量100克，兑水喷雾；② 75%百菌清可湿性粉剂，每亩用量100克，兑水喷雾；③ 25%氰烯菌酯悬浮剂，每亩用量40-60毫升，兑水喷雾；④ 40%戊唑醇悬浮剂，每亩用量15毫升，兑水喷雾；⑤ 70%甲基硫菌灵可湿性粉剂，每亩用量100克，兑水喷雾。在小麦抽穗扬花期施药，间隔7天再喷一次，视天气情况调整施药次数。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('小麦白粉病', '小麦粉病,小麦白霉病', '病害', '真菌性病害，危害叶片、茎秆和穗部，影响光合作用和产量。', '初期叶片表面出现白色霉斑，逐渐扩大呈圆形或椭圆形，霉斑表面有粉状物（分生孢子）。后期霉斑变为灰白色至浅褐色，病斑连片导致叶片黄枯。严重时茎秆、穗部也受害，籽粒灌浆不足，千粒重下降。病部后期散生黑色小点（闭囊壳）。', '喜温暖湿润气候，10-25℃最适，相对湿度70%以上易流行。春季雨水多、田间湿度大、氮肥过量、种植密度大、通风不良时发病重。品种抗性差异显著，感病品种在适宜条件下易爆发流行。', '1. 选用抗病品种，如郑麦366、济麦22等。2. 合理密植，改善通风透光。3. 平衡施肥，增施磷钾肥，避免过量施氮。4. 适时浇水，雨后及时排水，降低田间湿度。5. 收获后深耕灭茬，减少菌源。6. 发病初期及时清除病叶，减少传播。', '1. 15%三唑酮可湿性粉剂，每亩用50-70克，兑水喷雾。2. 25%嘧菌酯悬浮剂，每亩用20-30毫升，兑水喷雾。3. 12.5%烯唑醇可湿性粉剂，每亩用30-40克，兑水喷雾。4. 40%腈菌唑可湿性粉剂，每亩用20-30克，兑水喷雾。5. 75%百菌清可湿性粉剂，每亩用100-150克，兑水喷雾。发病初期施药，间隔7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('小麦蚜虫', '麦蚜,麦长管蚜,禾谷缢管蚜', '虫害', '刺吸小麦汁液，导致叶片发黄、植株矮缩，影响产量和品质。', '成虫和若虫群集在小麦叶片、茎秆和穗部刺吸汁液，导致叶片发黄、卷曲，植株矮缩生长不良。严重时叶片枯萎，穗部灌浆不足，籽粒不饱满，甚至整株枯死。蚜虫分泌的蜜露易诱发煤污病，影响光合作用。苗期受害后叶片出现黄色斑点，后期穗部受害导致籽粒秕瘦，千粒重下降。', '喜温暖干燥环境，适宜温度15-25℃，相对湿度低于70%时繁殖迅速。小麦返青至灌浆期是危害高峰，尤其干旱少雨年份易爆发。一年发生多代，以无翅孤雌生殖为主，繁殖速度快。天敌如瓢虫、草蛉、食蚜蝇数量少时易成灾。', '农业防治：合理轮作，清除田间杂草，培育抗虫品种。生物防治：保护利用天敌，释放瓢虫、草蛉等。物理防治：悬挂黄色粘虫板诱杀。化学防治：掌握防治适期，在蚜虫点片发生或百株蚜量达500头时及时用药，注意轮换用药，延缓抗性产生。', '1. 吡虫啉：每亩用10%可湿性粉剂20-30克，兑水30公斤喷雾。2. 啶虫脒：每亩用20%可湿性粉剂10-15克，兑水30公斤喷雾。3. 氟啶虫胺腈：每亩用22%悬浮剂10-15毫升，兑水30公斤喷雾。4. 抗蚜威：每亩用50%可湿性粉剂15-20克，兑水30公斤喷雾。5. 吡蚜酮：每亩用25%悬浮剂20-30毫升，兑水30公斤喷雾。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('小麦吸浆虫', '麦吸浆虫,红吸浆虫,黄吸浆虫', '虫害', '小麦穗部害虫，幼虫吸食麦粒汁液导致减产。', '小麦抽穗后，幼虫侵入麦穗吸食正在灌浆的麦粒汁液，导致麦粒空秕、不饱满。受害麦穗颖壳张口，麦粒表面有红褐色黏液，后期麦粒干瘪，用手轻搓有碎屑脱落。严重时整穗麦粒几乎全部被害，形成“白穗”，产量损失可达30%-70%。', '喜湿润环境，土壤含水量20%-30%最适。成虫羽化需土壤温度15℃以上，雨后湿度增大易爆发。一年发生1代，以老熟幼虫在土壤中越夏越冬。春季小麦拔节期幼虫化蛹，抽穗期羽化产卵。', '1. 农业防治：轮作倒茬，深耕灭蛹，清除田间杂草；2. 生物防治：保护天敌如瓢虫、步甲；3. 物理防治：设置诱虫灯诱杀成虫；4. 化学防治：重点在成虫羽化期和幼虫孵化期施药；5. 选用抗虫品种。', '1. 40%毒死蜱乳油：每亩50-75ml，兑水喷雾，防治成虫；2. 5%高效氯氟氰菊酯乳油：每亩30-40ml，兑水喷雾，防治幼虫；3. 48%毒死蜱颗粒剂：每亩2-3kg，撒施后浇水，防治土壤中幼虫；4. 20%吡虫啉可湿性粉剂：每亩10-15g，兑水喷雾，防治成虫；5. 10%高效氯氰菊酯乳油：每亩30-40ml，兑水喷雾，防治幼虫。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('小麦纹枯病', '小麦立枯病,小麦茎基腐病', '病害', '小麦纹枯病是一种真菌性土传病害，主要危害茎基部。', '初期在近地面叶鞘上产生淡褐色小斑点，后扩展为椭圆形云纹状病斑，中央灰白色，边缘褐色。病斑可环绕叶鞘，导致茎秆变软、易折。严重时病斑向上蔓延，影响养分输送，造成枯孕穗或白穗。湿度大时病部可见褐色菌核。', '病菌以菌核或菌丝在土壤中越冬，通过雨水、灌溉水传播。高温高湿（20-25℃）和多雨天气利于发病。连作田、播种过密、氮肥过量、田间湿度大的田块发病重。春季多雨年份病害流行风险高。', '1. 选用抗病品种，如济麦22、郑麦366等。2. 合理轮作，避免连作。3. 适期晚播，合理密植。4. 增施磷钾肥，避免氮肥过量。5. 清沟排渍，降低田间湿度。6. 拔除病株，减少菌源。7. 收获后深耕翻土，加速病残体分解。', '1. 25%戊唑醇可湿性粉剂，每亩30-40克，兑水喷雾，发病初期使用。2. 12.5%烯唑醇可湿性粉剂，每亩20-30克，兑水喷雾，间隔7-10天一次。3. 50%多菌灵可湿性粉剂，每亩100克，兑水喷雾，重点喷洒茎基部。4. 70%甲基托布津可湿性粉剂，每亩80-100克，兑水喷雾。5. 井冈霉素水剂，每亩50毫升，兑水喷雾，对纹枯病特效。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('麦蜘蛛', '麦红蜘蛛,麦叶螨', '虫害', '吸食小麦汁液，导致叶片发黄枯萎，影响产量。', '麦蜘蛛主要聚集在小麦叶片背面，用刺吸式口器吸食汁液，初期叶片出现黄白色斑点，随后逐渐连片变黄，严重时叶片枯萎卷曲，植株矮小，籽粒灌浆不足，甚至整株死亡。受害小麦生长受阻，分蘖减少，千粒重下降，最终导致减产。', '麦蜘蛛喜温暖干燥环境，春季气温回升至10℃以上时开始活动，15-20℃繁殖最快。干旱少雨、气温偏高的年份易爆发成灾。麦田杂草多、通风不良、植株密度大时发生较重。秋冬温暖、早春干旱少雨的气候条件有利于其越冬和繁殖。', '1. 农业防治：合理轮作，深耕灭茬，清除田间杂草；2. 选用抗虫品种，合理密植，改善通风透光条件；3. 生物防治：保护和利用天敌，如瓢虫、草蛉等；4. 物理防治：在田间设置黄色粘虫板诱杀；5. 化学防治：在害虫点片发生时及时喷药防治，避免大面积扩散。', '1. 阿维菌素：每亩用5%乳油10-15毫升，兑水30-40公斤喷雾；2. 哒螨灵：每亩用15%乳油20-30毫升，兑水30公斤喷雾；3. 螨死净：每亩用20%悬浮剂15-20毫升，兑水40公斤喷雾；4. 联苯肼酯：每亩用10%悬浮剂20-30毫升，兑水30公斤喷雾；5. 噻螨酮：每亩用10%可湿性粉剂20克，兑水40公斤喷雾。注意轮换用药，避免产生抗药性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('小麦全蚀病', '小麦立枯病,小麦黑脚病', '病害', '小麦根部和茎基部病害，导致枯白穗减产。', '幼苗期根部变褐，茎基部出现黑褐色病斑，拔节后茎基部1-2节处形成典型的\'黑脚\'症状，后期病株枯死，穗部呈枯白色。病部表面有黑色菌丝层，潮湿条件下可产生黑色小颗粒（子囊壳）。根系发育不良，易拔起，严重时整株枯死。', '病菌以菌丝体在病残体或土壤中存活，可通过种子、土壤、农机具传播。适宜发病温度为15-20℃，土壤湿度高时发病重。连作田、碱性土壤、偏施氮肥、播种过深的地块发病较重。小麦全生育期均可感病，以苗期和拔节期为侵染关键期。', '1. 选用抗病品种，如济麦22、郑麦366等；2. 实行3-5年轮作，避免与禾本科作物连作；3. 合理施肥，增施磷钾肥，避免偏施氮肥；4. 深翻土壤，清除病残体；5. 种子处理用2.5%适乐时种衣剂包衣；6. 发病初期及时拔除病株并带出田外销毁。', '1. 12.5%烯唑醇可湿性粉剂，每亩用30-40克，兑水喷雾；2. 25%三唑酮可湿性粉剂，每亩用50-60克，兑水喷雾；3. 70%甲基托布津可湿性粉剂，每亩用100克，兑水喷雾；4. 50%多菌灵可湿性粉剂，每亩用100克，兑水喷雾。在发病初期喷施，每隔7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('玉米大斑病', '玉米叶斑病,玉米大斑病枯病', '病害', '玉米叶片上形成大型梭形病斑，导致植株早衰减产。', '主要危害叶片，也可侵染叶鞘和苞叶。病斑初为水渍状青褐色小点，后扩展为梭形或长条形，中央灰褐色，边缘暗褐色，大小可达5-20厘米×1-3厘米。病斑常融合成大斑，导致叶片枯萎。湿度高时病斑上产生黑色霉层（分生孢子梗和孢子）。严重时植株提前枯死，籽粒不饱满，产量显著下降。', '病原为大斑突脐蠕孢菌（Exserohilum turcicum）。病菌以菌丝体或分生孢子在病残体上越冬，翌年产生分生孢子借风雨传播。高温高湿（20-28℃，相对湿度90%以上）易发病。连作田、种植感病品种、氮肥过多、植株密度大、通风不良时发病加重。', '1. 选用抗病品种，如郑单958、先玉335等。2. 轮作倒茬，与非禾本科作物实行3年以上轮作。3. 合理密植，改善通风透光条件。4. 科学施肥，增施磷钾肥，避免偏施氮肥。5. 及时清除病残体，减少初侵染源。6. 加强田间管理，雨后及时排水。', '1. 75%百菌清可湿性粉剂600倍液，喷雾防治，间隔7-10天一次。2. 50%多菌灵可湿性粉剂500倍液，发病初期喷雾，连续2-3次。3. 25%嘧菌酯悬浮剂1500倍液，均匀喷雾，持效期较长。4. 70%代森锰锌可湿性粉剂500倍液，保护性喷施。5. 40%苯醚甲环唑悬浮剂3000倍液，发病初期使用，防治效果显著。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('玉米小斑病', '玉米斑点病,玉米叶斑病', '病害', '由半知菌亚门真菌引起的玉米叶部病害，导致叶片枯死减产。', '初期叶片出现水渍状小斑点，后发展为椭圆形、黄褐色至褐色病斑，边缘清晰，中央灰白色，有同心轮纹。病斑融合后叶片枯死，严重时茎秆和苞叶也可受害。湿度大时病斑上产生灰黑色霉层（分生孢子及分生孢子梗）。病斑导致光合作用面积减少，植株早衰，果穗发育不良，籽粒灌浆不足，产量显著下降。', '病原菌以菌丝体或分生孢子在病残体上越冬，翌年借风雨传播。高温高湿（25-30℃，相对湿度90%以上）利于病害发生。连作田、种植密度过大、田间排水不良、氮肥过多或过少均会加重病情。品种抗性差异显著，感病品种在适宜条件下易爆发流行。', '1. 选用抗病品种，如郑单958、先玉335等；2. 实行轮作，与非禾本科作物隔年轮作；3. 合理密植，改善通风透光条件；4. 加强田间管理，及时清除病残体，合理施肥，增施磷钾肥，避免偏施氮肥；5. 雨季注意排水，降低田间湿度；6. 发病初期及时摘除下部病叶，减少菌源。', '1. 75%百菌清可湿性粉剂600-800倍液喷雾，间隔7-10天一次，连续2-3次；2. 50%多菌灵可湿性粉剂500倍液喷雾，重点喷洒叶片中下部；3. 25%吡唑醚菌酯乳剂2000倍液喷雾，兼具保护和治疗作用；4. 70%代森锰锌可湿性粉剂500倍液喷雾，发病前预防效果佳；5. 40%氟硅唑乳油8000倍液喷雾，对后期病害控制效果显著。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('玉米螟', '钻心虫,玉米钻心虫,玉米穗虫', '虫害', '玉米主要钻蛀性害虫，危害茎秆、叶片和果穗。', '幼虫蛀食玉米茎秆，造成叶片枯萎、植株倒伏；蛀食雄穗导致授粉不良；蛀食雌穗果柄和穗轴，造成籽粒腐烂、品质下降。茎秆被害后遇风易折断，影响产量。叶片被害呈现不规则透明斑点或孔洞，严重时叶片枯死。', '喜温暖湿润环境，年发生2-4代，以老熟幼虫在秸秆、穗轴中越冬。成虫趋光性强，卵多产于叶片中脉附近。夏季高温多雨利于发生，干旱则减轻危害。玉米连作、田间杂草多时虫口密度大。', '农业防治：选用抗虫品种，及时处理秸秆、穗轴，减少虫源；合理轮作，避免连作；生物防治：释放赤眼蜂寄生卵，喷洒白僵菌；物理防治：安装频振式杀虫灯诱杀成虫；化学防治：抓住关键时期（心叶末期、穗期）喷药防治。', '1. 5%氯虫苯甲酰胺悬浮剂：每亩30-40毫升，兑水喷雾，心叶末期灌心。2. 20%氯虫噻虫嗪悬浮剂：每亩10-15毫升，兑水喷雾，重点喷施玉米上部。3. 40%辛硫磷乳油：每亩50-75毫升，拌细土撒施于心叶内。4. 1.8%阿维菌素乳油：每亩30-40毫升，兑水喷雾，卵孵化盛期使用。5. Bt乳剂：每亩100-150毫升，兑水喷雾，低毒环保。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('玉米锈病', '玉米锈病,玉米锈斑病', '病害', '玉米锈病是由真菌引起的玉米叶部病害，导致叶片枯黄早衰。', '发病初期叶片出现淡黄色小斑点，后逐渐隆起形成黄褐色至锈褐色的夏孢子堆。孢子堆破裂后散出锈褐色粉末（夏孢子）。严重时叶片布满孢子堆，导致光合作用受阻，植株早衰，果穗发育不良，产量显著下降。茎秆和苞叶也可受害，症状类似叶片。', '高温高湿条件下易发病，气温20-30℃，相对湿度85%以上时孢子萌发和侵染迅速。夏孢子借风雨传播，重复侵染频繁。品种抗性差异大，连作田、氮肥过量、田间郁闭发病重。南方地区夏玉米发病较普遍，北方多在玉米生长中后期发生。', '选用抗病品种，如郑单958、农华101等。合理轮作，避免连作。合理密植，加强田间通风透光。平衡施肥，增施磷钾肥，避免偏施氮肥。及时清除病残体，减少初侵染源。发病初期摘除病叶，控制病情扩散。', '发病初期可喷施25%三唑酮可湿性粉剂1500倍液，或12.5%烯唑醇可湿性粉剂2000倍液，每7-10天一次，连续2-3次。也可用75%百菌清可湿性粉剂600倍液，或25%嘧菌酯悬浮剂1500倍液喷雾防治。注意轮换用药，避免抗药性产生。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('玉米丝黑穗病', '玉米黑穗病,玉米乌米病', '病害', '系统性真菌病害，致玉米雌雄穗变黑粉状', '苗期无症状，抽雄后雄穗基部膨大，内部充满黑粉；雌穗整个变成黑粉状，残留丝状维管束；病株矮化，分蘖增多，叶片浓绿；黑粉初为白色，后变黑，遇雨易散，残留丝状物。病株通常不结实或结畸形果穗。', '病菌以厚垣孢子在土壤、粪肥或种子表面越冬；土壤低温干旱（土温15-20℃）、播种过深、出苗慢利于发病；连作田、未腐熟粪肥、地下害虫多发病重；品种抗性差异显著。', '选用抗病品种如郑单958、先玉335；轮作倒茬3年以上，避免连作；施用腐熟有机肥，深耕土壤；适期播种，浅覆土，提高地温；苗期喷施生长调节剂促进早生快发；拔除病株并深埋或焚烧，减少菌源。', '可用25%三唑酮可湿性粉剂按种子重量0.2%拌种；或用2%立克秀种衣剂包衣，药种比1:500；发病初期喷施50%多菌灵可湿性粉剂600倍液，每隔7-10天一次，连续2-3次；或用75%百菌清可湿性粉剂500倍液喷雾防治。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('草地贪夜蛾', '秋粘虫,行军虫,玉米贪夜蛾', '虫害', '危害玉米的重大迁飞性害虫，暴食叶片致减产。', '初龄幼虫取食叶片呈半透明窗斑，三龄后暴食叶肉，残留叶脉形成不规则孔洞。高龄幼虫可钻入玉米心叶，造成“天窗”或蛀食雄穗。受害玉米生长受阻，严重时整株枯死，田间可见大量虫粪和残叶。', '喜温暖湿润环境，适温28-30℃。成虫夜间活动，可远距离迁飞，一年多代繁殖。卵多产于玉米叶片上，幼虫孵化后分散危害。干旱少雨时危害加重，南方地区可全年发生。', '1. 农业防治：种植抗虫品种，轮作倒茬，清除田间杂草和残株；2. 物理防治：安装杀虫灯、性诱剂诱捕成虫；3. 生物防治：释放天敌如赤眼蜂，喷施Bt制剂；4. 生态调控：合理布局作物，诱集带诱杀成虫。', '1. 甲氨基阿维菌素苯甲酸盐：每亩5-10毫升，兑水喷雾；2. 氯虫苯甲酰胺：每亩10-20克，均匀喷施叶片；3. 虫螨腈：每亩30-40毫升，重点喷洒心叶；4. 氟铃脲：每亩40-50毫升，低龄幼虫期使用；5. 苏云金杆菌：每亩100-150克，傍晚喷施效果最佳。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('玉米粗缩病', '玉米矮缩病,玉米条纹矮缩病', '病害', '玉米病毒病，由灰飞虱传播，导致植株矮化、畸形。', '发病初期心叶基部出现褪绿透明斑点，后发展为与叶脉平行的褪绿条纹。植株明显矮化，节间缩短，叶片宽厚、僵硬，呈暗绿色。根系发育不良，分蘖增多，雌穗发育不良或无穗，雄穗退化，严重时整株枯死。病株生长停滞，产量大幅下降。', '病原为玉米粗缩病毒（MRDV），主要通过灰飞虱持久性传播。病害发生与灰飞虱虫口密度密切相关，春季气温回升早、降雨少有利于灰飞虱繁殖和传病。玉米感病期主要在幼苗3-5叶期，若此时灰飞虱密度高，发病严重。邻近麦田的玉米田发病较重。', '1. 选用抗病品种，如郑单958、浚单20等。2. 调整播期，避开灰飞虱迁飞高峰。3. 清除田间及周边杂草，减少虫源。4. 合理密植，加强水肥管理，增强植株抗性。5. 灰飞虱迁入期及时喷施杀虫剂，切断传播途径。', '1. 10%吡虫啉可湿性粉剂，每亩15-20克，兑水喷雾，防治灰飞虱。2. 25%噻嗪酮可湿性粉剂，每亩30-40克，兑水喷雾，若虫期使用。3. 5%啶虫脒乳油，每亩30-40毫升，兑水喷雾，持效期较长。4. 20%异丙威乳油，每亩150-200毫升，兑水喷雾，速效性好。5. 50%抗蚜威可湿性粉剂，每亩10-15克，兑水喷雾，对灰飞虱高效。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('玉米茎腐病', '玉米青枯病,玉米茎基腐病', '病害', '玉米茎基部腐烂导致植株枯死的土传病害。', '多在玉米灌浆期发病，植株突然萎蔫，叶片灰绿色，茎基部水渍状腐烂，维管束变褐，根系腐烂。湿度大时可见白色菌丝，后期茎秆中空，易倒伏。果穗下垂，籽粒不饱满或腐烂。急性型全株迅速枯死，慢性型下部叶片先黄枯，逐渐向上发展。', '高温多雨季节（25-30℃）易发病，连作田、排水不良、土壤偏黏、氮肥过量、机械损伤或虫害多的地块发病重。镰刀菌腐霉复合侵染为主，病菌通过土壤、种子、病残体传播，从根部或茎基部伤口侵入。', '选用抗病品种，实行3年以上轮作，深耕土壤。合理密植，科学施肥（增施磷钾肥，避免偏施氮肥）。及时清除病残体，加强田间排水。苗期喷施杀菌剂预防，中耕时避免伤根。采用营养钵育苗移栽，减少根部损伤。', '1. 25%嘧菌酯悬浮剂：每亩30-40毫升，兑水喷雾，间隔7-10天，连用2次。2. 70%甲基硫菌灵可湿性粉剂：500倍液灌根，每株200毫升。3. 50%多菌灵可湿性粉剂：800倍液喷雾，重点喷茎基部。4. 3%恶霉灵水剂：600倍液灌根，发病初期使用。5. 72%霜脲·锰锌可湿性粉剂：600倍液喷雾，兼防其他病害。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('番茄晚疫病', '番茄疫病,番茄叶疫病', '病害', '毁灭性真菌病害，导致植株快速枯萎死亡。', '初期叶片出现暗绿色水渍状病斑，扩大后呈褐色，湿度大时病斑边缘产生白色霉层。茎部病斑呈长椭圆形，暗褐色，略凹陷。果实病斑不规则，硬化凹陷，表面有灰白色霉层。整株迅速萎蔫，似开水烫过，严重时全田枯死。', '低温高湿是发病关键，气温18-24℃，相对湿度95%以上最易发病。多雨多雾、露水重的季节流行快。连作田、排水不良、种植过密、氮肥过量加重发病。病菌通过风雨、灌溉水传播，从气孔或伤口侵入。', '选用抗病品种，与非茄科作物轮作3年以上。合理密植，加强通风，雨后及时排水。平衡施肥，增施磷钾肥，控制氮肥。发现病株立即拔除并深埋或烧毁，收获后彻底清除病残体。保护地栽培注意控制湿度，避免叶面长时间湿润。', '发病初期喷施72%霜脲锰锌可湿性粉剂600倍液，或68%精甲霜锰锌水分散粒剂800倍液，每隔7-10天喷一次，连续2-3次。也可用25%嘧菌酯悬浮剂1500倍液，或64%杀毒矾可湿性粉剂500倍液喷雾。注意交替用药，避免抗药性产生。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('番茄早疫病', '轮纹病,夏疫病', '病害', '真菌性病害，危害叶片、茎秆和果实，导致枯死和腐烂。', '叶片初现暗褐色小斑，扩大后呈同心轮纹状，边缘有黄色晕圈；茎部病斑椭圆形，凹陷，黑褐色；果实病斑凹陷，有同心轮纹，后期腐烂。高温高湿时病斑迅速扩展，整株枯死。', '病原为茄链格孢菌，通过风雨、农具传播。温度25-28℃、湿度80%以上易发病，连作、排水不良、植株徒长加重病情。', '选用抗病品种；轮作3年以上；合理密植，加强通风；平衡施肥，增施磷钾肥；及时清除病残体；发病初期喷施保护性药剂。', '推荐使用：1. 70%代森锰锌可湿性粉剂500倍液喷雾；2. 25%嘧菌酯悬浮剂1500倍液；3. 50%腐霉利可湿性粉剂1000倍液；7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('番茄灰霉病', '灰霉病,番茄灰霉病', '病害', '番茄灰霉病是由灰葡萄孢菌引起的真菌性病害，主要危害果实、叶片和茎秆。', '番茄灰霉病多从植株下部叶片开始发病，初期呈水渍状病斑，逐渐扩大为褐色至灰褐色，表面密生灰霉层。果实受害时，果蒂部先出现水渍状病斑，后软化腐烂，表面产生灰色霉层。茎秆受害时，出现椭圆形病斑，后导致植株枯萎。湿度大时，病斑迅速扩展，严重时整株死亡。', '灰霉病在低温高湿条件下易发生，适宜温度为20-25℃，相对湿度90%以上。病菌通过气流、雨水、农事操作传播，从伤口或自然孔口侵入。连作、通风不良、氮肥过多、植株密度大等均会加重病情。春季和秋季多雨潮湿时发病严重。', '1. 选用抗病品种，实行轮作；2. 加强栽培管理，合理密植，及时通风降湿；3. 及时清除病叶、病果，减少菌源；4. 控制氮肥，增施磷钾肥，提高植株抗性；5. 采用滴灌或膜下灌溉，避免叶面潮湿；6. 发病初期及时喷药保护。', '1. 50%腐霉利可湿性粉剂1000-1500倍液喷雾，每隔7-10天一次；2. 65%甲霜灵·锰锌可湿性粉剂600-800倍液喷雾，每隔5-7天一次；3. 40%嘧霉胺悬浮剂1000-1500倍液喷雾，每隔7-10天一次；4. 25%啶菌噁唑乳剂1500-2000倍液喷雾，每隔7-10天一次；5. 50%异菌脲可湿性粉剂1000-1500倍液喷雾，每隔7-10天一次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('番茄叶霉病', '番茄褐斑病,番茄煤霉病', '病害', '真菌性病害，主要危害叶片，影响光合作用', '初期叶片出现淡黄色病斑，后变为不规则褐色至深褐色，病斑表面生灰紫色至黑褐色霉层，严重时叶片枯萎脱落。茎部病斑椭圆形，凹陷，灰褐色。果实病斑多在果蒂附近，形成黑色坏死区，影响商品价值。', '高温高湿（20-25℃，相对湿度80%以上）易发病，温室大棚通风不良、连作、氮肥过量会加重病情。病原菌通过气流、种子、土壤传播，从气孔或伤口侵入。', '选用抗病品种，实行3年以上轮作，培育无病壮苗。加强田间管理，合理密植，及时整枝打杈，改善通风透光。控制温湿度，避免棚内湿度过高。发现病株及时清除，减少菌源。', '1. 50%多菌灵可湿性粉剂800倍液喷雾，7-10天一次，连续2-3次。2. 70%甲基托布津可湿性粉剂1000倍液喷雾，重点喷洒叶片背面。3. 75%百菌清可湿性粉剂600倍液喷雾，发病初期使用。4. 25%嘧菌酯悬浮剂1500倍液喷雾，保护兼治疗。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('番茄病毒病', '番茄花叶病,番茄条纹病', '病害', '番茄病毒病是由病毒侵染引起的系统性病害，导致植株畸形、矮化、减产甚至绝收。', '初期症状表现为叶片出现明脉、斑驳或花叶，随后叶片卷曲、皱缩、变黄或变紫，植株矮化，生长停滞。果实受害后出现斑驳、畸形，着色不均，品质下降。严重时整株枯死，果实失去商品价值。不同病毒种类症状有所差异，如烟草花叶病毒引起花叶，黄瓜花叶病毒引起蕨叶状。', '病毒主要通过蚜虫、粉虱等刺吸式口器昆虫传播，也可通过农事操作、种子和土壤传播。高温干旱、蚜虫虫口密度大、管理粗放时发病严重。连作地、杂草多的田块发病概率更高。番茄品种抗性差异明显，感病品种在适宜条件下易大面积流行。', '选用抗病毒品种，如抗TY、抗CMV的杂交种。实行轮作，与非茄科作物间隔3年以上。培育无病壮苗，加强田间管理，及时清除病株和杂草。防治传毒媒介，如用银灰色地膜驱避蚜虫，悬挂黄板诱杀。农事操作时注意消毒工具，避免人为传播。', '推荐使用20%盐酸吗啉胍可湿性粉剂500倍液喷雾，每7-10天一次，连续2-3次。或用1.5%植病灵乳剂1000倍液喷雾，增强植株抗性。同时配合0.5%菇类蛋白多糖水剂300倍液，提高抗病毒能力。发病初期及时用药，注意交替使用不同药剂，避免产生抗药性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('番茄青枯病', '细菌性枯萎病,青枯萎蔫病', '病害', '细菌性维管束病害，导致植株急性萎蔫死亡。', '发病初期，顶部叶片萎蔫下垂，傍晚恢复，次日中午不再恢复。茎秆维管束变褐，挤压有菌脓溢出。根部正常，但整株迅速枯死，叶片青绿不脱落。湿度大时，病茎表面可见白色霉层。果实染病后着色不均，维管束变褐坏死。', '高温高湿（25-30℃）易发病，土壤温度回升至20℃以上开始发病。连作地、酸性土壤、排水不良、地下害虫多发病重。病菌通过灌溉水、农具、昆虫传播，从根部或茎部伤口侵入。', '选用抗病品种，实行轮作（3年以上），避免与茄科作物连作。培育无病壮苗，嫁接防病。高畦栽培，合理密植，加强排水。及时清除病株，病穴用生石灰消毒。平衡施肥，增施磷钾肥，提高植株抗性。', '可选用72%农用硫酸链霉素可溶性粉剂3000-4000倍液，或20%噻菌铜悬浮剂500倍液，或47%春雷·王铜可湿性粉剂800倍液，或14%络氨铜水剂300倍液，或3%中生菌素可湿性粉剂600倍液，每7-10天喷灌一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('番茄根结线虫病', '番茄根瘤线虫病,番茄根腐线虫病', '虫害', '番茄根部形成根结，导致植株生长不良、产量下降。', '番茄根部形成大小不等的根结，初期为白色，后期变为褐色。根系发育不良，主根短小，侧根增多。地上部表现为植株矮小，叶片发黄，生长缓慢，结果少而小，严重时整株枯萎。根结内可见乳白色雌虫体，显微镜下可见虫卵。', '适宜温度为25-30℃，土壤湿度为40-60%时发病严重。连作地、沙质土壤、排水不良的地块发病重。病原线虫可通过土壤、灌溉水、农具、种子等传播。夏季高温多雨或冬季低温时发病较轻。', '实行轮作，与非寄主作物如禾本科作物轮作3年以上。选用抗病品种，如抗根结线虫的番茄品种。加强田间管理，及时清除病株残体，深翻土壤。采用无病土育苗，定植前土壤消毒。保持田间排水良好，避免积水。', '推荐使用1.8%阿维菌素乳剂1000倍液灌根，每株200-300毫升。10%噻唑膦颗粒剂每亩2-3公斤穴施。35%威百亩水剂每亩3-5公斤土壤处理。氟吡菌胺悬浮剂每亩100-150毫升灌根。生物农药淡紫紫孢菌制剂每亩2-3公斤沟施。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('黄瓜白粉病', '白粉病,面粉病', '病害', '真菌性病害，叶片表面白色粉状霉斑', '发病初期叶片正面出现白色小粉点，后扩大成圆形白粉斑，后期白粉层变为灰白色，叶片黄枯。严重时茎、叶柄、瓜蔓也可受害，病斑连片，植株早衰。白粉状物为病菌的菌丝体和分生孢子，后期产生黑色小颗粒（闭囊壳）。', '高温高湿（20-25℃）且通风不良时易发病。病原菌随病残体越冬，借气流传播。连作、氮肥过量、植株徒长、光照不足时发病加重。春秋季温差大、露水多时流行迅速。', '选用抗病品种；与非瓜类作物轮作；加强田间管理，合理密植，及时整枝打杈，改善通风透光；控制氮肥，增施磷钾肥；发病初期及时清除病叶、病株；棚室栽培注意控湿，避免叶面长时间结露。', '25%嘧菌酯悬浮剂1500倍液喷雾；40%氟硅唑乳剂8000倍液喷雾；15%三唑酮可湿性粉剂1500倍液喷雾；70%甲基托布津可湿性粉剂1000倍液喷雾；50%醚菌酯水分散粒剂3000倍液喷雾，每7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('黄瓜枯萎病', '黄瓜萎蔫病,黄瓜镰刀枯萎病', '病害', '黄瓜土传维管束病害，导致植株萎蔫死亡。', '发病初期植株下部叶片逐渐萎蔫，早晚恢复，后期不再恢复。茎基部纵裂，维管束变褐色。潮湿时茎部表面出现粉红色霉层（病原菌分生孢子）。病株根系发育不良，易拔起。发病后期整株枯死，但仍保持直立状。病株横切面可见维管束明显变色，为典型诊断特征。', '病原菌为尖孢镰刀菌，以菌丝、厚垣孢子在土壤或病残体中越冬。通过灌溉水、农具、昆虫传播。土温20-25℃、土壤偏酸（pH5.5-6.5）时发病严重。连作田、地势低洼、排水不良地块发病重。种子带菌可远距离传播。', '选用抗病品种如津春3号、津杂2号等。实行3-5年轮作，与非瓜类作物轮作。嫁接栽培（用南瓜作砧木）。土壤消毒定植前用石灰氮或太阳能消毒。增施磷钾肥，提高植株抗性。采用高畦栽培，雨后及时排水。发现病株立即拔除并带出田间深埋。', '发病初期可用50%多菌灵可湿性粉剂500倍液灌根，每株200-250ml，间隔7-10天一次，连续2-3次。或用70%甲基托布布可湿性粉剂800倍液喷雾，重点喷洒茎基部。也可用30%噁霉灵水剂1500倍液灌根。保护地可用10%嘧菌酯悬浮剂1500倍液喷雾。发病严重时，可用50%苯醚甲环唑水分散粒剂3000倍液灌根。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('黄瓜细菌性角斑病', '黄瓜角斑病,细菌性斑点病', '病害', '细菌性病害，叶片、果实形成角斑，导致减产。', '叶片初现水浸状小斑点，扩大后呈多角形黄褐色病斑，边缘有晕圈。湿度大时病斑溢出白色菌脓。果实病斑初为水渍状，后呈圆形或椭圆形，稍凹陷，溢出菌脓。严重时叶片枯萎，果实腐烂，植株早衰。茎蔓病斑呈水渍状长条形，易开裂。', '病原菌为丁香假单胞菌，通过风雨、昆虫、农事操作传播。高温高湿（20-25℃，相对湿度75%以上）易发病。连作、排水不良、通风差、植株伤口多时发病重。露地雨季或大棚通风不良时流行迅速。', '选用抗病品种，与非瓜类作物轮作。种子用55℃温水浸种15分钟或药剂消毒。大棚栽培加强通风，控制湿度。合理密植，及时清除病叶病果。农事操作后消毒工具。雨季及时排水，避免田间积水。发病初期及时喷药保护。', '1. 72%农用链霉素可湿性粉剂3000倍液，喷雾。2. 77%氢氧化铜可湿性粉剂500倍液，喷雾。3. 20%噻唑锌悬浮剂500倍液，喷雾。4. 46%氢氧化铜水分散粒剂1000倍液，喷雾。5. 30%噻菌酯悬浮剂2000倍液，喷雾。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('黄瓜灰霉病', '黄瓜灰霉病,黄瓜灰霉病病', '病害', '黄瓜灰霉病是一种由真菌引起的常见病害，主要危害叶片、茎和果实。', '初期在叶片上出现水渍状圆形病斑，逐渐扩大并呈灰褐色，表面产生灰色霉层。茎部受害后出现褐色病斑，严重时导致植株枯死。果实受害时，先在花蒂部出现水渍状病斑，迅速扩展至整个果实，表面密生灰色霉层，最终腐烂脱落。湿度大时病斑发展迅速，灰霉层明显。', '病原菌为灰葡萄孢菌，通过气流、雨水和农事操作传播。发病适宜温度为18-25℃，相对湿度90%以上时病情严重。温室大棚通风不良、湿度大、植株密度过高、氮肥施用过多等条件均易诱发此病。春季阴雨天气或大棚内夜间结露时发病尤为严重。', '选用抗病品种，实行轮作倒茬，与非瓜类作物间隔3年以上。加强栽培管理，合理密植，及时整枝打杈，改善通风透光条件。控制浇水，避免大水漫灌，降低棚内湿度。及时清除病叶、病果，带出田外集中销毁。在发病初期喷施保护性药剂，预防病害蔓延。', '推荐使用50%腐霉利可湿性粉剂1500倍液喷雾，每7-10天一次；或65%甲霜灵可湿性粉剂800倍液，间隔5-7天喷施；也可使用50%异菌脲可湿性粉剂1000倍液，重点喷施植株中下部。发病严重时，可交替使用上述药剂，避免产生抗药性。喷药时注意均匀覆盖叶片正反面及果实表面。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('黄瓜蔓枯病', '黄瓜黑腐病,黄瓜茎枯病', '病害', '真菌性病害，危害叶片、茎蔓和果实，造成枯萎腐烂。', '初期叶片出现近圆形黄褐色病斑，中央灰白色，轮纹明显；茎蔓受害产生椭圆形灰褐色病斑，绕茎扩展后导致植株萎蔫；果实染病形成圆形凹陷病斑，表面密生黑色小点。病部常溢出琥珀色胶质物，后期整株枯死。', '高温高湿（25-28℃）易发病，连作、排水不良、通风透光差加重病情。病菌通过风雨、农事操作传播，从伤口或气孔侵入。春秋季多雨季节发病重，温室大棚湿度大时常年发生。', '选用抗病品种，与非瓜类作物轮作3年以上；合理密植，加强通风降湿；及时清除病残体，减少初侵染源；采用膜下滴灌，避免大水漫灌；生长期喷施保护性药剂，预防为主。', '推荐使用：1）70%甲基托布可湿性粉剂800倍液喷雾；2）50%多菌灵可湿性粉剂600倍液灌根；3）75%百菌清可湿性粉剂600倍液喷雾；4）25%嘧菌酯悬浮剂1500倍液喷雾；5）10%苯醚甲环唑水分散粒剂1500倍液喷雾。每7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('柑橘黄龙病', '黄梢病,青果病', '病害', '柑橘毁灭性病害，由韧皮部杆菌引起，可致植株死亡。', '初期病树出现黄化枝条，叶片斑驳黄化，叶脉黄化明显；果实小而畸形，着色不均，果皮硬实，味酸苦；根部腐烂，植株生长衰弱，逐渐枯死。病树叶片常表现为缺锌、缺锰等症状，但施肥难以缓解。', '主要通过柑橘木虱传播，嫁接和带病苗木也可扩散。温暖潮湿气候利于木虱繁殖，病害发生严重。25-30℃为病菌适宜温度，夏季高温多雨时病害扩展迅速。', '1. 选用无病苗木，严格执行植物检疫；2. 及时挖除病树，销毁病源；3. 加强果园管理，合理施肥，增强树势；4. 统一防治柑橘木虱，切断传播途径；5. 建立无病母本园，培育健康种苗。', '目前无特效药剂治疗，防治以预防为主。可选用噻虫嗪（1000倍液）或吡虫啉（2000倍液）防治柑橘木虱；发病初期喷施宁南霉素（500倍液）或盐酸吗啉胍（1000倍液）抑制病情，需结合综合防治措施。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('柑橘溃疡病', '溃疡病,柑橘细菌性溃疡病', '病害', '细菌性病害，导致叶片、枝干和果实溃疡性病斑。', '叶片初期出现黄色油渍状小病斑，后扩大成灰褐色、木栓化、中央凹陷的溃疡斑，周围有黄色晕圈；枝干病斑呈梭形，隆起破裂；果实病斑类似叶片，木栓化明显，影响品质和商品价值。病斑可穿透果皮，导致落果和树势衰弱。', '高温高湿（25-30℃）易发病，风雨传播病原菌；苗木带菌、修剪工具、昆虫（如潜叶蛾）可传播；管理粗放、树势衰弱、伤口多发病重；品种间抗性差异大，甜橙、柚类感病性强。', '选用无病苗木，加强检疫；合理修剪，避免伤口，及时清除病枝叶；加强肥水管理，增强树势；果园生草覆盖，改善小气候；及时防治传虫害，减少传播途径；发病区严格消毒工具，减少人为传播。', '推荐药剂：1. 77%氢氧化铜可湿性粉剂500倍液喷雾；2. 20%噻唑锌悬浮剂300倍液喷雾；3. 45%代森铵水剂800倍液喷雾；4. 2%春雷霉素水剂600倍液喷雾；5. 30%王铜可湿性粉剂600倍液喷雾。发病初期开始用药，7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('柑橘潜叶蛾', '绘图虫,鬼画符,潜叶虫', '虫害', '幼虫潜食叶片，形成银白色弯曲隧道，影响光合作用。', '幼虫孵化后潜入嫩叶表皮下取食，形成银白色弯曲的隧道，隧道内有黑色虫粪。叶片受害后卷曲变硬，易脱落，影响树势和果实品质。严重时新梢生长受阻，枝条纤弱，幼果易脱落。被害叶片失去光合作用能力，导致树体营养积累不足。', '喜温暖潮湿环境，年均温20-28℃、相对湿度80%以上时发生严重。每年发生9-12代，以蛹或老熟幼虫在被害叶内越冬。夏梢和秋梢受害最重，春梢较轻。成虫夜间活动，卵多散产于嫩叶背面。', '1. 农业防治：及时修剪被害枝叶，清除虫源；合理修剪，通风透光；避免偏施氮肥，增强树势。2. 生物防治：释放寄生蜂，如潜蛾姬小蜂。3. 物理防治：利用黄板诱杀成虫。4. 化学防治：在新梢萌发期喷药保护，重点防治夏秋梢。', '1. 25%噻虫嗪水分散粒剂：3000-4000倍液喷雾，持效期15天。2. 1.8%阿维菌素乳油：3000-5000倍液喷雾，触杀胃毒作用。3. 20%甲维盐微乳剂：4000-6000倍液喷雾，高效低毒。4. 10%吡虫啉可湿性粉剂：2000-3000倍液喷雾，内吸性强。5. 24%螺虫乙酯悬浮剂：3000-4000倍液喷雾，持效期长。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('柑橘炭疽病', '柑橘黑斑病,柑橘轮斑病', '病害', '柑橘炭疽病是一种由真菌引起的常见病害，危害叶片、枝干和果实。', '叶片上出现圆形或不规则形病斑，边缘褐色，中央灰白色，上生黑色小点。枝干上出现椭圆形病斑，稍凹陷，皮层开裂。果实受害后出现褐色病斑，表面凹陷，潮湿时产生粉红色黏孢子。严重时导致落叶、枝枯和果实腐烂，影响产量和品质。', '高温高湿环境易发病，尤其是雨季或台风后。病原菌通过风雨、昆虫传播，从伤口或自然孔口侵入。树势衰弱、管理粗放、通风不良的果园发病严重。品种间抗病性差异明显，甜橙、柚类较感病。', '加强栽培管理，合理修剪，改善通风透光条件。及时清除病枝、病叶和病果，减少初侵染源。增施有机肥，增强树势，提高抗病能力。雨季前喷施保护性药剂，发病后及时治疗。选择抗病品种，新建果园避免在病区选址。', '推荐使用25%嘧菌酯悬浮剂1500倍液喷雾，7-10天一次；70%甲基硫菌灵可湿性粉剂800倍液，发病初期喷施；10%苯醚甲环唑水分散粒剂2000倍液，间隔14天喷一次；50%多菌灵可湿性粉剂500倍液，发病高峰期使用；75%百菌清可湿性粉剂600倍液，预防兼治疗。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('柑橘锈壁虱', '锈蜘蛛,柑橘锈螨', '虫害', '柑橘主要害螨，吸食汁液导致果皮锈色粗糙', '叶片受害呈灰褐色，失去光泽；果实受害初期出现灰绿色斑点，逐渐变为褐色至锈色，果皮粗糙如砂纸，果小味酸；嫩枝被害后扭曲变形，严重时引起落叶落果。受害果实商品价值大幅降低。', '高温干燥气候（25-30℃）最适宜繁殖，年发生10-20代；5-6月开始危害，7-8月达高峰；管理粗放、树冠郁闭、通风不良的果园受害更重；天敌（如捕食螨、草蛉）少时易爆发。', '1. 加强栽培管理：合理修剪，改善通风透光；2. 保护天敌：避免滥用广谱杀虫剂；3. 及时监测：5月起定期检查叶片和果实；4. 果园生草：保持生态平衡；5. 清除越冬虫源：冬季清园，剪除病虫枝叶。', '1. 73%炔螨特乳油1500-2000倍液，喷雾防治成螨；2. 20%哒螨灵可湿性粉剂2000-3000倍液，触杀性强；3. 5%噻螨酮乳油1500-2000倍液，杀卵效果好；4. 1.8%阿维菌素乳油3000-4000倍液，生物制剂，安全间隔期7天；5. 24%螺螨酯悬浮剂4000-5000倍液，持效期长。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('柑橘介壳虫', '矢尖蚧,糠片蚧,褐圆蚧', '虫害', '吸食柑橘汁液，导致枝叶枯萎，果实品质下降。', '介壳虫群集于柑橘枝干、叶片和果实表面，吸食汁液导致叶片发黄、脱落，枝条干枯，果实生长受阻，表面出现凹陷或畸形。严重时树势衰弱，产量大幅下降，甚至整株死亡。虫体分泌蜜露易诱发煤烟病，影响光合作用。', '温暖湿润环境有利繁殖，每年发生2-4代，以雌成虫或若虫越冬。春季气温回升后开始活动，若虫期是防治关键期。通风不良、树冠郁闭的果园发生较重，偏施氮肥的植株更易受害。', '加强栽培管理，合理修剪增强通风透光，及时清除受害枝叶。冬季清园，喷施石硫合剂消灭越冬虫源。保护天敌如瓢虫、草蛉等生物防治。生长期定期检查，发现虫害及时隔离处理，避免扩散。', '推荐使用40%毒死蜱乳油1000倍液喷雾，或25%噻嗪酮可湿性粉剂1500倍液，或22%氟啶虫胺腈悬浮剂2000倍液。重点喷洒枝干、叶片背面及果实表面，每隔7-10天一次，连续2-3次。注意轮换用药，避免产生抗药性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('苹果腐烂病', '苹果树腐烂病,烂皮病', '病害', '苹果树主要枝干病害，导致树皮腐烂坏死。', '初期病斑红褐色，水渍状，略隆起，后失水凹陷，呈黑褐色。病皮易剥离，烂皮有酒糟味。病斑环绕枝干一周时，上部枝叶枯萎死亡。果实染病呈暗褐色圆形病斑，软腐凹陷，表面有黑色小点。', '病菌以菌丝体在病组织中越冬，通过风雨、昆虫传播。春季低温多雨、夏季高温干旱易诱发。树势衰弱、修剪伤口、冻害、虫害等是发病主要诱因。', '加强栽培管理，增强树势；合理修剪，及时清除病枝；刮除病斑后涂抹保护剂；冬季树干涂白防冻；果园通风透光，降低湿度；避免机械损伤和过量施氮肥。', '1. 45%代森铵水剂100倍液涂抹病斑；2. 50%多菌灵可湿性粉剂500倍液喷雾；3. 70%甲基托布津可湿性粉剂800倍液喷雾；4. 1%硫酸铜溶液消毒伤口；5. 50%退菌特可湿性粉剂500倍液喷雾。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('苹果褐斑病', '苹果褐腐病,苹果叶斑病', '病害', '苹果树主要叶部病害，导致早期落叶，影响树势和产量。', '初期叶片出现褐色小斑点，后扩展为圆形或不规则形病斑，边缘清晰，中央灰白色，边缘深褐色，病斑上产生黑色小颗粒（分生孢子盘）。严重时病斑连片，叶片变黄早落，果实着色差，品质下降，树势衰弱。', '多雨高湿季节（6-9月）易发病，尤其是7-8月降雨频繁时。病原菌以菌丝或分生孢子在病落叶中越冬，通过风雨传播。树势衰弱、通风不良、排水差的地块发病重。', '1. 清除病落叶，减少初侵染源；2. 合理修剪，改善通风透光；3. 加强肥水管理，增强树势；4. 选用抗病品种；5. 生长期喷药保护，雨后及时补喷。', '1. 10%苯醚甲环唑水分散粒剂3000倍液，喷雾；2. 75%百菌清可湿性粉剂600-800倍液，喷雾；3. 50%多菌灵可湿性粉剂800-1000倍液，喷雾；4. 25%吡唑醚菌酯乳剂2000倍液，喷雾；5. 70%代森锰锌可湿性粉剂500-700倍液，喷雾。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('苹果轮纹病', '苹果粗皮病,苹果轮斑病', '病害', '主要危害枝干和果实，导致树皮粗糙和果实腐烂。', '枝干上出现褐色圆形病斑，中心突起，边缘开裂，呈轮纹状。果实受害初期出现水渍状褐色小斑，后迅速扩大，形成同心轮纹，病斑处果肉腐烂，但病果不脱落。叶片上产生褐色圆形病斑，有同心轮纹，后期病斑中部灰白色，上生黑色小点。', '多雨潮湿天气利于发病，病菌主要通过风雨传播，从伤口或自然孔口侵入。树势衰弱、伤口多的果园发病重。春季气温回升快，湿度大时，孢子大量产生，侵染高峰期在果实膨大期至成熟期。', '加强栽培管理，合理修剪，改善通风透光条件，增强树势。及时清除病枝、病果，减少菌源。果实套袋可有效减少侵染。冬季刮除枝干病斑，涂抹杀菌剂保护。雨季注意排水，降低果园湿度。', '推荐使用70%甲基托布可湿性粉剂800倍液喷雾，或50%多菌灵可湿性粉剂600倍液，或75%百菌清可湿性粉剂600倍液，或40%氟硅唑乳油8000倍液。在发病初期开始喷药，每隔10-15天一次，连续2-3次，注意交替使用不同药剂，避免产生抗药性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('苹果红蜘蛛', '山楂叶螨,苹果叶螨', '虫害', '苹果树主要害螨，吸食叶片汁液导致落叶减产。', '成螨若螨聚集叶片背面刺吸汁液，初期叶片出现失绿小斑点，逐渐连成斑块，严重时叶片黄褐脱落。受害树光合作用下降，果实小而着色差，树势衰弱。螨虫多在叶背主脉两侧拉丝结网，螨体红色或暗红色，肉眼可见爬行。', '高温干燥（20-30℃）利于繁殖，年发生代数多（北方5-7代，南方10代以上）。春季气温回升早，降雨少则大发生。天敌（瓢虫、草蛉等）少或化学农药滥用易爆发。管理粗放、树冠郁闭果园虫口密度高。', '农业防治：清园刮除老翘皮，清除落叶杂草；合理修剪改善通风；果园生草保护天敌。物理防治：悬挂黄板诱杀，夏季树干涂白阻螨。生物防治：释放捕食螨，喷施生物农药（苦参碱、印楝素）。化学防治：关键时期（花前、花后、麦收前）精准用药，轮换用药抗性。', '1. 5%噻螨酮2000倍液，喷雾防治成若螨。2. 20%哒螨灵2000倍液，速效性好，持效期7-10天。3. 1.8%阿维菌素3000倍液，杀卵兼杀成螨，对天敌安全。4. 24%螺螨酯4000倍液，持效期长，适合早期控制。5. 40%三唑锡1500倍液，对已产生抗性种群有效，避开高温使用。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('苹果蚜虫', '苹果黄蚜,苹果卷叶蚜', '虫害', '刺吸苹果嫩梢叶片汁液，导致卷叶、生长受阻', '若蚜和成蚜群集于苹果嫩梢、叶片背面刺吸汁液，被害叶片向正面纵卷呈筒状，叶面不平整，颜色变黄；嫩梢生长受阻，扭曲变形；严重时落花落果，树势衰弱；分泌蜜露诱发煤污病，影响光合作用', '春季气温回升至10℃以上开始活动，4-5月为繁殖高峰期；干旱少雨、温度偏高（20-25℃）时繁殖迅速；通风不良、树冠郁闭的果园发生较重；以卵在枝条芽缝、树皮裂缝中越冬，春季孵化后开始危害', '加强栽培管理，合理修剪改善通风透光；及时清除受害枝叶，减少虫源；保护天敌（瓢虫、草蛉、寄生蜂等），避免滥用广谱农药；春季萌芽前喷施石硫合剂清园；生长期监测虫情，早发现早防治', '1. 10%吡虫啉可湿性粉剂3000倍液喷雾；2. 25%噻虫嗪水分散粒剂5000倍液喷雾；3. 1.8%阿维菌素乳油3000倍液喷雾；4. 20%啶虫脒可溶性粉剂3000倍液喷雾；5. 40%毒死蜱乳油1500倍液（花前使用）', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('桃小食心虫', '桃蛀果蛾,苹果食心虫', '虫害', '蛀食苹果果实，导致果实腐烂脱落。', '幼虫蛀入果实内部，蛀孔处有虫粪排出，果实逐渐腐烂脱落。被害果表面有针尖大小的蛀入孔，周围稍凹陷，有虫粪堆积。幼虫在果内蛀食果肉，形成弯曲的隧道，果心被蛀食一空，仅剩果皮和种子。被害果易脱落，不堪食用。', '一年发生1-2代，以老熟幼虫在土中结茧越冬。5-6月化蛹，6-7月羽化成虫，产卵于果实表面。卵期7-10天，幼虫孵化后蛀入果实。幼虫期20-30天，老熟幼虫脱果入土。高温多雨年份发生严重，管理粗放的果园受害更重。', '1. 冬季深翻土壤，消灭越冬幼虫；2. 及时摘除虫果，集中深埋或烧毁；3. 果实套袋，防止产卵；4. 设置性诱剂诱捕器，监测成虫发生；5. 加强果园管理，合理修剪，改善通风透光条件。', '1. 48%毒死蜱乳油1500倍液，喷雾防治成虫；2. 20%甲维盐悬浮剂3000倍液，喷雾防治幼虫；3. 25%灭幼脲悬浮剂1500倍液，喷雾防治低龄幼虫；4. 10%氯虫苯甲酰胺悬浮剂2000倍液，喷雾防治幼虫；5. 5%高效氯氟氰菊酯乳油2000倍液，喷雾防治成虫和幼虫。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('葡萄霜霉病', '葡萄白腐病,葡萄灰霉病', '病害', '葡萄霜霉病是一种由卵菌纲真菌引起的毁灭性病害。', '主要危害叶片、新梢、花序和幼果。叶片初期出现水渍状黄色小斑点，后扩大为不规则黄褐色病斑，背面产生白色霜霉状物。严重时叶片枯焦脱落，影响光合作用。幼果受害后变硬、萎缩，表面覆盖白色霉层，最终脱落。新梢受害后扭曲畸形，生长停滞。', '多发生在温暖潮湿的环境，温度20-25℃，湿度90%以上时易爆发。雨水多、露水重、通风不良的果园发病严重。病原菌通过风雨传播，从气孔或伤口侵入。春季低温多雨易初侵染，夏季高温高湿易再侵染。', '1. 选用抗病品种，如巨峰、赤霞珠等；2. 加强栽培管理，合理修剪，保持通风透光；3. 及时清除病叶、病枝，减少菌源；4. 控制氮肥，增施磷钾肥，增强植株抗性；5. 雨季注意排水，降低田间湿度。', '1. 58%甲霜灵·锰锌可湿性粉剂500倍液喷雾；2. 72%霜脲·锰锌可湿性粉剂800倍液喷雾；3. 25%嘧菌酯悬浮剂1500倍液喷雾；4. 50%烯酰吗啉可湿性粉剂2000倍液喷雾；5. 1%波尔多液（硫酸铜:石灰:水=1:1:100）喷雾。发病初期开始用药，7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('葡萄白腐病', '穗枯病,水烂病', '病害', '葡萄果实、枝蔓和叶片的真菌性病害，导致腐烂和枯死。', '果实发病初期出现浅褐色水渍状病斑，迅速蔓延至全果，果面密生灰白色小颗粒，果粒软腐脱落。枝蔓受害形成褐色、凹陷的溃疡斑，病部表皮纵裂，严重时枝干枯死。叶片发病时产生褐色至灰褐色病斑，有不明显的同心轮纹，后期干枯破裂。病部在潮湿条件下产生灰白色至黑色的分生孢子器。', '病菌以分生孢子器和菌丝体在病组织中越冬，通过风雨和昆虫传播。高温多雨（25-30℃）和高湿（相对湿度85%以上）条件利于发病。果园排水不良、通风透光差、树势衰弱、伤口多时发病严重。果实着色至成熟期为发病高峰期。', '1. 选用抗病品种，如巨峰、玫瑰香等。2. 加强栽培管理，合理修剪改善通风透光，及时排水，增强树势。3. 清除病枝、病叶、病果，集中烧毁或深埋，减少初侵染源。4. 果穗套袋可有效预防。5. 生长期及时防治其他病虫害，减少伤口。', '1. 50%多菌灵可湿性粉剂800倍液，发病初期喷雾，每7-10天一次，连续2-3次。2. 75%百菌清可湿性粉剂600倍液，全株喷雾，重点保护果穗。3. 70%甲基托布津可湿性粉剂1000倍液，喷雾防治，兼治其他病害。4. 25%嘧菌酯悬浮剂1500倍液，发病前或初期喷雾，保护期长。5. 1:0.7:200波尔多液，发病前喷施，预防效果良好。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('葡萄炭疽病', '葡萄晚腐病,葡萄苦腐病', '病害', '葡萄果实和枝叶的真菌性病害，导致腐烂和减产。', '主要危害果实，初期形成水渍状褐色小斑点，后扩大为圆形凹陷病斑，表面产生橘红色黏稠孢子团。叶片上出现圆形病斑，中央灰白色，边缘褐色。蔓上病斑椭圆形，凹陷，易开裂。果实成熟期发病严重，导致腐烂脱落，影响品质和产量。', '高温多雨季节（25-30℃）易发病，尤其是果实着色至成熟期。病原菌通过风雨传播，从伤口或自然孔口侵入。果园排水不良、通风透光差、栽培密度过大、管理粗放会加重病情。品种间抗性差异明显，欧亚种较美洲种易感病。', '1. 选用抗病品种如巨峰、赤霞珠等；2. 加强栽培管理，合理修剪，保持通风透光；3. 及时清除病枝、病叶、病果，减少菌源；4. 控制氮肥，增施磷钾肥，增强树势；5. 雨季注意排水，降低果园湿度；6. 果实套袋可有效减少侵染。', '1. 75%百菌清可湿性粉剂600-800倍液，发病初期喷雾；2. 50%多菌灵可湿性粉剂800-1000倍液，每7-10天喷一次；3. 25%嘧菌酯悬浮剂1500-2000倍液，保护兼治疗；4. 70%甲基硫菌灵可湿性粉剂1000倍液，发病前预防；5. 40%氟硅唑乳油8000-10000倍液，严重时使用。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('葡萄黑痘病', '疮痂病,鸟眼病', '病害', '真菌性病害，危害叶片、果实和嫩梢，形成黑色病斑。', '叶片初期出现红褐色小斑点，扩大后中央灰白色，边缘褐色，穿孔。果实上产生圆形病斑，中央凹陷，灰白色，边缘紫褐色，似鸟眼状。嫩梢、叶柄、卷须受害后出现椭圆形病斑，中央凹陷，灰褐色，后期开裂。严重时导致叶片畸形、果实脱落、枝梢枯死。', '病菌以菌丝体在病枝、病叶中越冬，通过风雨传播。高温多雨、湿度大（相对湿度80%以上）时发病严重。果园通风不良、排水不畅、氮肥过多会加重病情。春季多雨、夏季高温高湿是发病高峰期。', '1. 选用抗病品种如巨峰、玫瑰香等；2. 清除病枝、病叶，集中烧毁；3. 加强栽培管理，合理修剪，保持通风透光；4. 控制氮肥，增施磷钾肥；5. 雨季及时排水，降低湿度；6. 萌芽前喷施石硫合剂清园。', '1. 10%苯醚甲环唑水分散粒剂2000倍液，喷雾；2. 75%百菌清可湿性粉剂600倍液，喷雾；3. 50%多菌灵可湿性粉剂800倍液，喷雾；4. 25%嘧菌酯悬浮剂1500倍液，喷雾；5. 70%代森锰锌可湿性粉剂500倍液，喷雾。发病初期开始用药，7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('葡萄白粉病', '葡萄白粉病,葡萄白毛病', '病害', '真菌性病害，危害叶片、果实和新梢，表面覆白粉。', '叶片正面出现白色粉状霉斑，后期变为灰白色，病斑逐渐扩大连片，叶片卷曲枯萎。幼果染病果面覆盖白色粉状物，果皮变硬，龟裂，酸涩不堪食用。新梢染病后生长受阻，节间缩短，严重时枯死。病部后期出现黑色小粒点，为病菌的闭囊壳。', '高温干旱与闷热交替的气候条件下易发病，最适温度25-28℃，湿度较低时发病重。栽培管理不当，如氮肥过多、通风不良、枝叶过密，会加重病情。病菌以菌丝体在被害组织上越冬，风雨传播，春季开始侵染。', '1. 选用抗病品种，如巨峰、玫瑰香等。2. 加强栽培管理，合理修剪，保持通风透光，及时清除病枝病叶。3. 科学施肥，增施磷钾肥，避免氮肥过量。4. 秋季彻底清园，消灭越冬病菌。5. 生长期加强监测，发现病株及时处理。', '1. 25%嘧菌酯悬浮剂1500倍液喷雾，间隔7-10天一次。2. 40%氟硅唑乳剂8000倍液喷雾，重点喷施叶片背面。3. 70%甲基托布可湿性粉剂1000倍液喷雾，发病初期使用。4. 50%多菌灵可湿性粉剂800倍液喷雾，连续2-3次。5. 12.5%烯唑醇可湿性粉剂2000倍液喷雾，注意轮换用药。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('柑橘红蜘蛛', '红蜘蛛,锈壁虱,柑橘全爪螨', '虫害', '柑橘主要害虫，吸食汁液导致叶片黄化脱落', '成螨若螨群集叶背吸汁，叶片出现灰白色失绿小斑点，严重时叶片灰白脱落，果实表面形成锈色斑，影响光合作用和果实品质。受害嫩叶扭曲变形，新梢生长受阻，树势衰弱，产量显著下降。', '高温干燥（20-30℃）、通风不良时爆发。每年3-4月越冬卵孵化，5-6月、9-10月为两个高峰期。雨水少、湿度低（相对湿度60%以下）时繁殖迅速。管理粗放、树势衰弱的果园受害更重。', '1. 农业防治：合理修剪增强通风，清除杂草，加强水肥管理增强树势；2. 生物防治：释放捕食螨（如胡瓜钝绥螨）、瓢虫等天敌；3. 物理防治：悬挂黄色粘虫板；4. 化学防治：抓住关键防治期，避免滥用农药保护天敌。', '1. 阿维菌素：5000倍液喷雾，重点喷叶背；2. 螺螨酯：4000倍液喷雾，持效期长；3. 唑螨酯：2000-3000倍液喷雾，杀卵杀螨；4. 丁醚脲：1500倍液喷雾，对成螨若螨有效；5. 炔螨特：73%乳油2000倍液喷雾，注意高温时使用。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('苹果斑点落叶病', '苹果褐斑病,苹果叶斑病', '病害', '苹果叶片上出现褐色斑点，导致早期落叶，影响树势和产量。', '叶片初现褐色小斑点，后扩大为直径2-6mm的圆形或不规则病斑，中心灰白色，边缘紫褐色，病斑上可见黑色小粒点（分生孢子盘）。严重时病斑相连，叶片焦枯脱落。嫩枝、果实也可受害，出现褐色小斑，病部凹陷。', '高温多雨季节（6-8月）易发病，尤其是雨后高温。病菌以菌丝或分生孢子在落叶或枝梢病部越冬，通过风雨传播。树势衰弱、通风不良、排水差、氮肥过量会加重病情。', '1. 选用抗病品种（如嘎啦、红星）；2. 清除病枝落叶，减少初侵染源；3. 合理修剪，改善通风透光；4. 科学施肥，增施磷钾肥，避免偏施氮肥；5. 雨季及时排水，降低湿度。', '1. 10%苯醚甲环唑水分散粒剂3000倍液，喷雾；2. 50%多菌灵可湿性粉剂800倍液，喷雾；3. 70%代森锰锌可湿性粉剂600倍液，喷雾；4. 25%吡唑醚菌酯乳油2000倍液，喷雾；5. 75%百菌清可湿性粉剂600倍液，喷雾。发病初期开始喷药，7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('葡萄灰霉病', '葡萄灰腐病,葡萄灰星病', '病害', '葡萄果实和叶片上产生灰色霉层，导致腐烂和落果。', '主要危害果实、花序、叶片和新梢。果实发病初期出现褐色病斑，迅速扩展并覆盖灰色霉层，最终腐烂脱落。花序受害后变褐腐烂，幼果易脱落。叶片产生不规则褐色病斑，表面生灰霉，后期干枯。新梢病斑呈梭形，凹陷，表面密生灰霉，严重时枝条枯死。潮湿条件下病部产生大量灰色分生孢子，传染性强。', '多雨潮湿气候是发病主要条件，尤其是花期至果实成熟期遇连续阴雨。温度20-25℃、相对湿度90%以上时发病严重。伤口（如机械伤、虫伤）和衰弱植株易感病。病原菌通过气流、雨水传播，潜伏侵染后遇适宜条件爆发。果园通风不良、树冠郁闭、排水不畅会加重病情。', '1. 农业防治：选用抗病品种，合理修剪保持通风透光；及时清除病枝、病果并深埋；控制氮肥，增施磷钾肥增强树势；雨季注意排水，降低湿度。2. 生态调控：避雨栽培可显著降低发病；果园生草调节微环境。3. 物理防治：萌芽前喷施石硫合剂清园。4. 生物防治：利用拮抗微生物如木霉菌制剂喷雾预防。', '1. 50%腐霉利可湿性粉剂1000-1500倍液，花前、花后各喷1次。2. 40%嘧霉胺悬浮剂1000倍液，发病初期喷雾，间隔7-10天一次。3. 25%嘧菌酯悬浮剂1500倍液，保护性喷雾，预防效果好。4. 70%甲基硫菌灵可湿性粉剂800倍液，发病初期使用。5. 50%异菌脲可湿性粉剂1000倍液，兼治其他病害，注意轮换用药避免抗性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('葡萄透翅蛾', '葡萄透翅蛾,葡萄卷叶蛾,葡萄钻心虫', '虫害', '幼虫蛀食葡萄枝蔓，导致枝条枯萎或死亡。', '幼虫蛀食葡萄嫩梢、枝蔓髓部，受害处肿大，叶片萎蔫变黄，枝条生长停滞。蛀孔外有虫粪和木屑，严重时枝条枯死。被害部位表皮有脱落的痕迹，用手按压有松软感。幼虫可蛀入多年生枝蔓，影响植株生长和果实产量。', '该虫害每年发生1代，以老熟幼虫在被害枝蔓内越冬。5-6月化蛹，6-7月成虫羽化产卵，卵多产于嫩梢叶腋或新梢基部。幼虫孵化后蛀入枝条，7-8月为危害盛期。高温干旱年份发生较重，管理粗放、通风不良的果园受害更严重。', '1. 冬季修剪时剪除被害枝蔓并集中烧毁，减少越冬虫源。2. 加强栽培管理，合理修剪，保持通风透光，增强树势。3. 成虫羽化期设置黑光灯诱杀成虫。4. 及时检查，发现被害枝条立即剪除并处理。5. 在成虫产卵前树干涂白，阻止成虫产卵。', '1. 20%氰戊菊酯乳油2000倍液，喷雾防治成虫和初孵幼虫。2. 40%氧化乐果乳油1000倍液，注入蛀孔内或喷雾。3. 2.5%高效氯氟氰菊酯乳油1500倍液，喷雾防治幼虫。4. 48%毒死蜱乳油1500倍液，喷雾防治成虫。5. 1.8%阿维菌素乳油3000倍液，喷雾防治幼虫。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('棉花枯萎病', '棉花萎蔫病,棉花镰刀菌枯萎病', '病害', '棉花维管束系统真菌病害，导致植株枯萎死亡。', '苗期表现为子叶变黄、萎蔫，根部导管变褐；成株期下部叶片先出现黄色网状斑，逐渐向上扩展，叶片枯萎下垂但不脱落，剖茎可见维管束变褐。病株矮小，结铃少，严重时整株枯死。典型症状是叶片黄化、枯萎与维管束褐变并存，潮湿条件下茎基部可见粉红色霉层。', '病菌在土壤和病残体中越冬，通过种子、土壤、流水传播。发病适温为20-30℃，土温25-28℃时最严重。连作田、酸性土壤、偏施氮肥、地势低洼或排水不良的地块发病较重。苗期低温多雨或灌水过多会加重病情。', '选用抗病品种如中棉所35、鲁棉研28等；实行3年以上轮作，与禾本科作物轮作；增施磷钾肥，避免偏施氮肥；合理灌溉，雨后及时排水；播种前用多菌灵或苯醚甲环唑浸种；发现病株及时拔除并深埋，病穴用石灰消毒。', '1. 50%多菌灵可湿性粉剂500倍液灌根，每株100-200ml；2. 70%甲基托布津可湿性粉剂800倍液喷雾，7-10天一次；3. 25%嘧菌酯悬浮剂1500倍液灌根；4. 10%苯醚甲环唑水分散粒剂2000倍液喷雾；5. 50%萎锈灵可湿性粉剂1000倍液灌根。发病初期用药，交替使用效果更佳。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('棉花黄萎病', '棉花萎蔫病,棉花黄枯病', '病害', '棉花维管束病害，导致叶片黄化、植株萎蔫。', '发病初期下部叶片叶脉失绿，叶片边缘上卷，逐渐发展为全叶黄化，叶片主脉保持绿色呈掌状斑驳。病株矮化，蕾铃脱落，维管束变为黄褐色至褐色。急性型发病时，叶片突然萎蔫下垂，但叶片不脱落，后期整株枯死。病株剖开可见茎秆维管束变褐，木质部导管堵塞。', '病菌以菌丝体、微菌核在土壤病残体或种子内外越冬，通过土壤、灌溉水、农机具传播。高温（25-30℃）多雨季节发病重，连作田、排水不良田发病严重。棉花现蕾后开始发病，花铃期达发病高峰。品种抗性差异显著，感病品种在适宜条件下发病率可达80%以上。', '1. 选用抗病品种如中棉所系列、冀棉系列等；2. 实行3年以上轮作，与禾本科作物轮作；3. 种子处理：用50%多菌灵可湿性粉剂500倍液浸种24小时；4. 加强田间管理：合理密植，平衡施肥，及时清除病株；5. 采用地膜覆盖栽培，提高地温；6. 无病土育苗，培育无病壮苗。', '1. 50%多菌灵可湿性粉剂800倍液灌根，每株200-250毫升；2. 70%甲基托布津可湿性粉剂1000倍液喷雾，7-10天一次，连续2-3次；3. 75%百菌清可湿性粉剂600倍液喷雾，重点喷洒植株下部叶片；4. 10%苯醚甲环唑水分散粒剂2000倍液灌根，每株150毫升；5. 25%嘧菌酯悬浮剂1500倍液喷雾，发病初期使用，间隔10-14天。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('棉蚜', '腻虫,蜜虫,油汗', '虫害', '刺吸棉株汁液，导致卷叶、落蕾，传播病毒病。', '棉蚜多群集于棉花嫩叶背面、顶尖及嫩茎上，刺吸汁液，导致叶片卷曲、皱缩，植株生长停滞。严重时叶片发黄、脱落，蕾铃大量脱落。蚜虫分泌蜜露覆盖叶面，易诱发煤污病，影响光合作用。受害棉株矮小，发育迟缓，结铃减少。', '棉蚜喜温暖干燥环境，适温24-28℃，相对湿度50-70%。每年发生10-20代，以卵在越冬寄主上或以成若虫在温室植物上越冬。春季气温回升后迁入棉田，5-6月和9-10月为危害高峰期。干旱年份或偏施氮肥的棉田危害加重。', '1. 农业防治：选用抗虫品种，合理轮作，清除田间杂草和越冬寄主。2. 生物防治：保护天敌（瓢虫、草蛉、食蚜蝇），释放天敌昆虫。3. 物理防治：悬挂黄色粘虫板，诱杀成蚜。4. 化学防治：重点防治点片发生，避免大面积喷药。', '1. 吡虫啉：10%可湿性粉剂3000倍液喷雾，重点喷施叶背。2. 啶虫脒：20%可溶性粉剂3000-4000倍液喷雾。3. 阿维菌素：1.8%乳油3000倍液喷雾，兼治螨类。4. 氟啶虫胺腈：50%水分散粒剂15000倍液喷雾，持效期长。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('棉花红蜘蛛', '棉叶螨,红叶螨,火龙', '虫害', '刺吸棉叶汁液，致叶片黄枯，植株早衰。', '成螨、若螨聚集在叶片背面，刺吸汁液，叶片出现黄白色小斑点，逐渐扩大成红褐色斑块，严重时叶片枯焦脱落，植株生长停滞，蕾铃大量脱落，棉株早衰，产量显著下降。', '高温干燥环境有利繁殖，最适温度25-30℃，相对湿度60%以下。每年发生10-20代，世代重叠严重。干旱年份或棉田周围有杂草时发生重。棉株生长中后期若遇高温干旱，易爆发成灾。', '农业防治：合理轮作，清除田间杂草，及时拔除病株；水肥管理：增施磷钾肥，保持田间湿润；生物防治：保护天敌如瓢虫、草蛉等；化学防治：早发现早防治，避免滥用农药。', '1. 阿维菌素：3000倍液喷雾，重点喷叶片背面。2. 螨虫腈：2000倍液喷雾，7-10天一次。3. 哒螨灵：1500倍液喷雾，持效期15天左右。4. 噻螨酮：2000倍液喷雾，对卵、幼螨高效。5. 联苯肼酯：3000倍液喷雾，速效性好，持效期长。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('大豆花叶病毒病', '大豆病毒病,大豆花叶', '病害', '大豆花叶病毒病导致叶片花叶、矮缩、荚果畸形减产。', '幼苗感病后出现花叶、斑驳，叶片皱缩、卷曲，植株矮化。成株期叶片沿叶脉出现褪绿斑驳，呈典型花叶症状，严重时叶片畸形、坏死，荚果小而少，豆粒发育不良，产量显著下降。病株根系发育不良，根瘤数量减少，抗逆性降低。', '病毒主要通过带毒种子、蚜虫（如豆蚜、桃蚜）汁液摩擦传播。高温干旱（25-30℃）条件下发病重，蚜虫数量大时传播迅速。重茬地块、管理粗放、杂草多的田块发病较重。品种抗性差异明显，感病品种发病率可达50%以上。', '选用抗病品种，如\'中豆32\'、\'合丰50\'等。实行3年以上轮作，避免连作。及时清除田间杂草和病株，减少毒源。播种前用10%磷酸三钠溶液浸种20分钟，杀死种子表面病毒。苗期及时防治蚜虫，切断传播途径。加强田间管理，合理密植，增强植株抗病力。', '发病初期喷洒20%病毒A可湿性粉剂500倍液，或1.5%植病灵乳剂1000倍液，每隔7-10天喷1次，连续2-3次。也可用5%菌毒清水剂300倍液喷雾，或0.5%抗病毒1号水剂300倍液，配合喷施叶面肥（如0.2%磷酸二氢钾）增强植株抗性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('大豆根腐病', '大豆根腐病,大豆猝倒病,大豆立枯病', '病害', '大豆根部腐烂，导致植株枯死，产量显著下降。', '幼苗期根部出现褐色病斑，逐渐扩展至茎基部，导致皮层腐烂、缢缩，植株矮化、萎蔫。成株期根部变褐、坏死，主根和侧根大量减少，根瘤稀少。病株叶片发黄、脱落，严重时整株枯死。病部可见白色或粉红色霉层，为病原菌的菌丝或孢子。', '病菌以菌丝体或厚垣孢子在土壤或病残体中越冬，通过土壤、灌溉水或农事操作传播。高温高湿（25-30℃）条件下发病严重，连作田、排水不良、土壤黏重或偏酸性地块发病重。幼苗期遇低温多雨或田间积水，病情加重。', '选用抗病品种，实行3年以上轮作，避免与豆科作物连作。深翻土壤，增施有机肥，改善土壤透气性。合理密植，加强田间排水，避免田间积水。播种前进行种子处理，可用种衣剂拌种。及时清除病株，减少菌源。', '推荐药剂：1. 70%恶霉灵可湿性粉剂，按种子重量0.3%拌种；2. 25%嘧菌酯悬浮剂，每亩40-60毫升稀释喷雾；3. 50%多菌灵可湿性粉剂，每亩100克稀释灌根；4. 70%甲基托布津可湿性粉剂，每亩100克稀释喷雾；5. 10%苯醚甲环唑水分散粒剂，每亩30克稀释喷雾。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('大豆蚜虫', '腻虫,蜜虫,豆蚜', '虫害', '刺吸大豆汁液，导致植株生长受阻、叶片卷曲。', '成虫和若虫群集于大豆嫩叶、嫩茎和花荚上，刺吸汁液，导致叶片卷曲、发黄，植株矮化，生长停滞。严重时叶片枯萎脱落，荚果发育不良，籽粒秕瘦，影响产量和品质。同时，蚜虫分泌蜜露，易引发煤污病，阻碍光合作用。', '大豆蚜虫喜温暖干燥环境，适宜温度为20-25℃，相对湿度低于70%时繁殖迅速。一年可发生多代，以卵在寄主植物上越冬，春季孵化后迁移至大豆危害。干旱少雨的年份易爆发成灾，且传播病毒病风险增加。', '1. 选用抗虫品种，如‘黑农44’、‘合丰50’等；2. 合理轮作，避免连作；3. 清除田间杂草和残株，减少越冬虫源；4. 合理密植，改善通风透光；5. 保护和利用天敌，如瓢虫、草蛉、食蚜蝇等；6. 早期发现中心虫株及时拔除销毁。', '1. 吡虫啉：每亩用10%吡虫啉可湿性粉剂20-30克，兑水喷雾；2. 啶虫脒：每亩用3%啶虫脒乳油40-50毫升，兑水喷雾；3. 阿维菌素：每亩用1.8%阿维菌素乳油30-40毫升，兑水喷雾；4. 氰戊菊酯：每亩用20%氰戊菊酯乳油15-20毫升，兑水喷雾；5. 噻嗪酮：每亩用25%噻嗪酮可湿性粉剂30-40克，兑水喷雾。注意轮换用药，避免抗药性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('大豆食心虫', '大豆蛀荚蛾,豆荚螟', '虫害', '幼虫蛀食豆荚，导致大豆产量和品质下降。', '幼虫孵化后从豆荚边缘蛀入，在豆荚内取食豆粒，形成虫道，豆粒表面可见圆形小孔。受害豆荚豆粒残缺、破碎，品质显著下降，严重时豆荚内仅剩虫粪和碎屑。被害豆荚不易脱落，但豆粒重量减轻，发芽率降低。后期豆荚表面可见蛀孔和褐色粪便，用手挤压有虫体排出。', '大豆食心虫一年发生1-2代，以老熟幼虫在土中越冬。成虫在7-8月羽化，夜间活动，趋光性强。卵多产于豆荚茸毛间，孵化期5-7天。幼虫期20-30天，适宜温度25-28℃，相对湿度70-80%。干旱或高温天气发生较轻，多雨潮湿天气利于虫害爆发。连作地、豆荚毛密品种受害较重。', '1. 农业防治：选用抗虫品种，合理轮作，避免连作；及时清除田间落荚和秸秆，减少越冬虫源；2. 物理防治：成虫期设置黑光灯诱杀；3. 生物防治：释放赤眼蜂寄生卵，喷施苏云金杆菌等生物农药；4. 化学防治：在成虫盛发期和卵孵化期及时喷药，重点喷洒豆荚部位。', '1. 2.5%高效氯氟氰菊酯乳油，每亩30-40毫升，兑水喷雾；2. 40%毒死蜱乳油，每亩50-75毫升，兑水喷雾；3. 20%甲维盐悬浮剂，每亩15-20毫升，兑水喷雾；4. 10%吡虫啉可湿性粉剂，每亩20-30克，兑水喷雾。于成虫产卵盛期或幼虫初孵期喷施，重点喷洒豆荚，间隔7-10天一次，连喷2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('大豆灰斑病', '大豆褐斑病,大豆叶斑病', '病害', '真菌性病害，危害叶片、荚果和籽粒，导致减产和品质下降。', '叶片初生褪绿小斑点，后扩展为圆形或不规则形灰褐色病斑，中央灰白色，边缘褐色，病斑上生有灰黑色霉层（病原菌分生孢子）。严重时叶片枯黄脱落，荚果上病斑不规则，深褐色，内部籽粒干瘪、变褐。病斑多从叶片尖端和边缘开始，逐渐向内扩展。', '高湿多雨气候（相对湿度80%以上，温度20-25℃）易发病。病原菌以菌丝体在病残体或种子上越冬，风雨传播。连作田、排水不良、种植密度过大、氮肥过量发病重。大豆品种间抗病性差异显著。', '选用抗病品种，如\'黑农44\'、\'绥农14\'等。轮作倒茬（与非豆科作物3年以上），深翻土壤清除病残体。合理密植，改善通风透光；平衡施肥，增施磷钾肥，控氮防徒长。及时排水，降低田间湿度。种子播前用50%多菌灵可湿性粉剂拌种。', '发病初期喷施50%多菌灵可湿性粉剂800倍液，或75%百菌清可湿性粉剂600倍液，或70%代森锰锌可湿性粉剂500倍液，每7-10天喷一次，连续2-3次。也可用25%嘧菌酯悬浮剂1500倍液喷雾，注意交替用药，避免抗药性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('白菜软腐病', '烂根病,细菌性软腐病', '病害', '细菌性病害，导致白菜腐烂发臭。', '初期植株外叶萎蔫，晴天中午恢复，后外叶下垂贴地。叶柄基部或根茎处出现水渍状斑，逐渐扩大变软腐烂，病部流出灰褐色粘稠液体，散发恶臭。病斑向内扩展，导致整株腐烂，仅残留维管束呈乱麻状。病叶易脱落，留有残茎。', '病原菌在土壤、病残体或虫体越冬，通过雨水、灌溉水、昆虫传播。高温多雨（25-30℃）、高湿（相对湿度85%以上）易发病。连作地块、地下害虫多、机械伤口多、排水不良发病重。', '选用抗病品种，与非十字花科作物轮作。深翻土壤，清洁田园，及时清除病株。合理密植，加强通风，避免大水漫灌。防治地下害虫（如菜青虫、根蛆）减少伤口。发现病株立即拔除并带出田外深埋。', '72%农用链霉素可湿性粉剂3000-4000倍液喷雾；77%氢氧化铜可湿性粉剂500倍液灌根；20%噻唑锌悬浮剂1000倍液喷雾；3%中生菌素可湿性粉剂800倍液喷雾；50%氯溴异氰尿酸可湿性粉剂1500倍液喷雾。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('白菜霜霉病', '白菜白霉病,白菜霜霉', '病害', '真菌性病害，主要危害叶片，导致减产。', '初期叶片出现淡黄色不规则病斑，后扩大为黄褐色至褐色多角形病斑，湿度大时叶背产生白色霉层。严重时叶片枯黄脱落，植株矮小，包心不实，影响产量和品质。病斑常受叶脉限制呈多角形，是典型特征。', '病原为芸薹霜霉菌，喜温暖潮湿环境。气温10-20℃，相对湿度70%以上时易发病。多雨、多雾、露水重的季节或田块发病重。连作、排水不良、种植过密、氮肥过多均会加重病情。病菌通过风雨、昆虫传播，从气孔或表皮侵入。', '选用抗病品种，与非十字花科作物轮作。合理密植，加强通风透光。平衡施肥，增施磷钾肥，避免偏施氮肥。雨后及时排水，降低田间湿度。收获后清除病残体，深埋或焚烧。发病初期及时摘除病叶，带出田外处理。', '可选用72%霜脲锰锌可湿性粉剂600-800倍液喷雾，或58%甲霜灵锰锌可湿性粉剂500倍液，每7-10天一次，连续2-3次。也可用69%烯酰吗啉锰锌可湿性粉剂600-800倍液，或75%百菌清可湿性粉剂600倍液喷雾。注意交替用药，避免产生抗药性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('白菜病毒病', '白菜花叶病,白菜毒素病', '病害', '由病毒侵染引起，导致白菜畸形、坏死减产。', '发病初期叶片出现明脉、褪绿斑，后发展为花叶、皱缩、畸形。心叶扭曲，叶脉坏死，植株矮化。病株生长缓慢，结球松散或不结球。严重时全株黄化，枯死。病果表面有褐色坏死斑，品质下降。', '高温干旱（25℃以上）利于病毒繁殖和传播。蚜虫是主要传播媒介，通过刺吸汁液传播。土壤缺肥、管理粗放、连作地块发病重。种子带病或田间杂草寄主也可引发病害。', '选用抗病品种，实行轮作。及时清除田间杂草和病株。合理密植，加强肥水管理，增强植株抗性。苗期覆盖防虫网，防治蚜虫。发现病株立即拔除并深埋或焚烧。', '20%病毒A可湿性粉剂500倍液喷雾，7-10天一次；1.5%植病灵乳剂1000倍液喷雾；5%菌毒清水剂300倍液喷雾；0.5%抗毒丰水剂300倍液喷雾；混合喷施0.1%硫酸锌溶液增强抗性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('白菜黑斑病', '黑斑病,叶枯病', '病害', '真菌性病害，致白菜叶片枯死减产', '初期叶片出现褐色小斑点，后扩大为圆形或不规则形病斑，中央灰白色，边缘褐色，具明显同心轮纹。严重时病斑融合成大斑，致叶片枯黄脱落。茎和花梗上病斑长椭圆形，黑褐色，稍凹陷。湿度大时病斑表面生黑色霉层，即病原菌的分生孢子梗和分生孢子。', '病菌以菌丝体或分生孢子在病残体、种子或土壤中越冬。通过风雨、昆虫传播，从气孔或伤口侵入。高温多雨、湿度大（相对湿度85%以上）、植株生长衰弱时发病重。连作地块、排水不良、偏施氮肥发病严重。', '1. 选用抗病品种，如北京新1号、晋菜3号等。2. 实行轮作，与非十字花科作物隔年轮作。3. 收获后彻底清除病残体，深翻土壤。4. 合理密植，加强通风；科学施肥，增施磷钾肥，避免偏施氮肥。5. 雨季及时排水，降低田间湿度。6. 种子用50℃温水浸种30分钟或用杀菌剂拌种。', '1. 75%百菌清可湿性粉剂600倍液喷雾，间隔7-10天一次，连续2-3次。2. 70%代森锰锌可湿性粉剂500倍液喷雾，发病初期开始使用。3. 50%异菌脲可湿性粉剂1000倍液喷雾，重点喷洒叶片背面。4. 25%嘧菌酯悬浮剂1500倍液喷雾，持效期较长。5. 40%氟硅唑乳油8000倍液喷雾，对黑斑病有较好防效。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('菜青虫', '菜粉蝶幼虫,白粉蝶幼虫', '虫害', '菜粉蝶幼虫啃食叶片，严重时仅剩叶脉。', '幼虫孵化后群集叶背啃食叶肉，形成透明斑块，3龄后分散危害，将叶片吃成孔洞或缺刻，严重时仅残留叶脉，影响白菜生长和产量。粪便污染叶片，易诱发软腐病。被害叶片失去商品价值，严重时整株死亡。', '每年发生4-5代，以蛹在菜地附近墙缝、杂草或枯枝落叶中越冬。成虫喜在十字花科植物产卵，卵散产于叶背。温暖潮湿（20-25℃）、多雨季节利于繁殖，世代重叠严重。春秋季为危害高峰期。', '1. 农业防治：轮作倒茬，清除田间残株落叶，减少越冬虫源；种植诱集植物如甘蓝诱杀成虫。2. 物理防治：覆盖防虫网，人工捕捉幼虫和蛹。3. 生物防治：释放赤眼蜂寄生卵，喷施苏云金杆菌（Bt）制剂。4. 化学防治：掌握在幼虫3龄前施药，避免长期使用同种农药。', '1. 氯虫苯甲酰胺悬浮剂：每亩10-15毫升，兑水30公斤喷雾，持效期15天。2. 甲氨基阿维菌素苯甲酸盐：每亩5-8克，兑水喷雾，低毒高效。3. 虫酰肼悬浮剂：每亩30-40毫升，在低龄幼虫期使用，安全间隔期7天。4. 氰戊菊酯乳油：每亩20-30毫升，注意轮换使用，避免抗药性。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('辣椒疫病', '辣椒疫霉病,辣椒根腐疫病', '病害', '辣椒疫病是一种毁灭性真菌病害，可导致植株枯萎和果实腐烂。', '苗期茎基部出现水渍状病斑，逐渐缢缩枯萎成猝倒；成株期叶片出现暗绿色水渍状病斑，迅速扩大变褐；茎部病斑呈黑褐色，严重时整株枯萎；果实上产生暗绿色水渍状病斑，迅速腐烂，表面生白霉；根部受害后变褐腐烂，病部可见白色菌丝体。', '高温高湿是发病主要条件，气温25-30℃、相对湿度90%以上时病害迅速蔓延；连作地块、排水不良、氮肥过量会加重发病；雨季或大水漫灌后病情加重；病菌通过雨水、灌溉水、农具传播，从伤口或自然孔口侵入。', '选用抗病品种如\'湘研15号\'、\'辣研6号\'；实行3年以上轮作，避免与茄科作物连作；高畦栽培，合理密植，雨后及时排水；平衡施肥，增施磷钾肥，控制氮肥；发现病株立即拔除并带出田外深埋；加强田间通风，降低湿度。', '发病初期喷施72%霜脲锰锌可湿性粉剂600倍液，或58%甲霜灵锰锌可湿性粉剂500倍液；也可用69%烯酰吗啉锰锌可湿性粉剂800倍液喷雾；根部发病可用25%甲霜灵可湿性粉剂1000倍液灌根，每株灌药液250毫升，间隔7-10天一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('辣椒炭疽病', '辣椒黑斑病,辣椒轮斑病', '病害', '辣椒炭疽病是一种由真菌引起的常见病害，主要危害叶片和果实。', '叶片上出现圆形或不规则形病斑，边缘褐色，中央灰白色，后期病斑上产生黑色小点（分生孢子盘）。果实受害时，出现水渍状褐色斑点，逐渐扩大为圆形或椭圆形凹陷病斑，表面密生黑色小点，严重时果实腐烂脱落。茎部病斑呈椭圆形，稍凹陷，灰褐色，后期纵裂。', '高温高湿条件下易发病，温度20-30℃，相对湿度80%以上时病害发展迅速。病菌通过风雨、昆虫传播，从伤口或气孔侵入。连作地、排水不良、种植密度过大、通风透光差的地块发病重。', '选用抗病品种，实行轮作，与非茄科作物间隔2-3年。加强田间管理，合理密植，及时清除病残体，改善通风透光条件。平衡施肥，增施磷钾肥，提高植株抗病力。雨季及时排水，防止田间积水。', '可选用70%甲基硫菌灵可湿性粉剂800倍液喷雾，或75%百菌清可湿性粉剂600倍液，或50%多菌灵可湿性粉剂500倍液，或25%嘧菌酯悬浮剂1500倍液，或10%苯醚甲环唑水分散粒剂1500倍液，每隔7-10天喷一次，连续2-3次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('辣椒病毒病', '辣椒花叶病,辣椒丛枝病', '病害', '辣椒病毒病是由病毒侵染引起的系统性病害，严重影响产量和品质。', '辣椒病毒病主要表现为叶片花叶、黄化、卷曲、畸形，植株矮化，生长迟缓。严重时叶片出现坏死斑，果实变小、畸形，果面出现褐色坏死条纹，导致落花落果。不同病毒株系症状差异较大，如花叶型叶片出现黄绿相间斑驳，蕨叶型叶片变窄呈线状，丛枝型植株侧枝丛生，顶部叶片呈簇状。', '病毒主要通过蚜虫、粉虱等刺吸式口器昆虫传播，也可通过种子、土壤、机械摩擦传播。高温干旱（25-35℃）、蚜虫虫口密度大、管理粗放、连作地块发病重。辣椒生长前期感染症状明显，后期感染症状较轻。不同品种抗病性差异显著，感病品种在适宜条件下发病迅速。', '1. 选用抗病品种，如\'湘研15号\'、\'辣研8号\'等；2. 种子消毒，用10%磷酸三钠溶液浸种20分钟；3. 培育无病壮苗，培育无病苗床；4. 加强田间管理，及时清除病株、杂草，合理密植，平衡施肥；5. 物理防治，覆盖银灰色地膜驱避蚜虫；6. 生物防治，释放天敌如瓢虫、草蛉等控制蚜虫。', '1. 20%病毒A可湿性粉剂500倍液喷雾，每7天一次，连续2-3次；2. 1.5%植病灵乳剂1000倍液喷雾，发病初期使用；3. 5%菌毒清水剂300倍液喷雾，每10天一次；4. 0.5%抗毒丰水剂300倍液喷雾，重点喷洒叶片背面；5. 10%宁南霉素水剂1500倍液喷雾，兼治细菌性病害。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('黄瓜霜霉病', '黑毛,跑马干', '病害', '专性寄生真菌性病害，导致叶片枯死减产。', '初期叶片出现淡黄色不规则病斑，湿度大时叶背产生灰紫色霉层。病斑逐渐扩大连片，叶片枯黄干枯但不脱落。严重时整株叶片枯死，果实生长受阻。病原菌为卵菌门霜霉属，以孢子囊随气流传播。', '低温高湿环境（15-25℃），叶面持续4小时以上水膜易发病。连作、排水不良、氮肥过量、通风差加重病情。孢子囊在10-30℃均可萌发，20-25℃最适。', '选用抗病品种，实行轮作，深翻土壤。高畦栽培，合理密植，保持通风。控制浇水，避免叶面潮湿。发病初期及时清除病叶，带出田外深埋。增施磷钾肥，提高植株抗性。', '72%霜脲锰锌可湿性粉剂600倍液喷雾，7天1次。58%甲霜灵锰锌可湿性粉剂500倍液，5-7天喷1次。64%杀毒矾可湿性粉剂500倍液，间隔7天。25%嘧菌酯悬浮剂1500倍液，10天1次。烯酰吗啉水分散粒剂1500倍液，5-7天喷1次。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('辣椒青枯病', '辣椒细菌性枯萎病,辣椒维管束病', '病害', '细菌性维管束病害，导致辣椒枯萎死亡。', '发病初期，植株下部叶片萎蔫，早晚可恢复，后逐渐加重。茎部维管束变褐，切开可见导管变黑。病株叶片保持绿色，但迅速枯萎。潮湿时茎部可见菌脓，干燥时仅表现为系统性萎蔫。根系外观正常，但内部已腐烂。', '高温高湿环境（25-30℃）易发病，土壤湿度大、排水不良加重病情。连作地块、土壤酸性、线虫危害或根部机械损伤可增加发病几率。病菌通过灌溉水、农具、病残体传播，从根部伤口侵入。', '选用抗病品种，实行3年以上轮作。采用高畦栽培，改善排水。培育无病壮苗，避免伤根。生长期合理施肥，增强植株抗性。及时清除病株，病穴用石灰消毒。农具用1%高锰酸钾溶液消毒。', '可选用72%农用链霉素可溶性粉剂3000倍液，或77%氢氧化铜可湿性粉剂500倍液灌根，每株200-300毫升。发病初期用20%噻菌铜悬浮剂500倍液喷雾，间隔7-10天一次，连续2-3次。也可用14%络氨铜水剂300倍液灌根，兼防其他土传病害。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('辣椒灰霉病', '辣椒灰霉腐烂病,辣椒花腐病', '病害', '辣椒灰霉病由灰葡萄孢菌引起，主要危害花、叶和果实。', '发病初期，叶片出现水渍状褐色病斑，逐渐扩大并形成灰褐色霉层。花朵受害后变褐软腐，表面密生灰色霉状物。果实多从蒂部开始发病，呈灰褐色软腐，表面产生大量灰色霉层，严重时整果脱落。高湿度条件下，病部迅速扩展，导致植株枯死。', '病菌以菌丝体或分生孢子在病残体上越冬，通过气流、雨水传播。低温高湿（20-25℃）是发病主要条件，尤其在连续阴雨、大棚通风不良时易爆发。病原菌从伤口或衰老组织侵入，植株生长衰弱时发病加重。', '1. 选用抗病品种，实行轮作，避免连作；2. 加强田间管理，合理密植，及时清除病残体；3. 控制大棚湿度，适时通风降湿；4. 平衡施肥，增强植株抗病力；5. 发病初期及时摘除病叶、病果，带出田外深埋或焚烧。', '1. 50%腐霉利可湿性粉剂1000-1500倍液喷雾，7-10天一次；2. 50%异菌脲可湿性粉剂1000倍液，重点喷洒花和果实；3. 40%嘧霉胺悬浮剂1000倍液，均匀喷施植株各部位；4. 65%甲霜灵·锰锌可湿性粉剂600倍液，交替使用以抗药性；5. 25%啶菌噁唑乳油1500倍液，保护性治疗兼施。', 'AI生成');
INSERT INTO pest_knowledge (name, aliases, type, summary, symptoms, conditions, prevention, medicine, source) VALUES ('棉铃虫', '棉铃实夜蛾,玉米穗虫,番茄果虫', '虫害', '棉铃虫是一种多食性害虫，主要危害棉花的花蕾、铃和叶片，也可危害其他多种作物的果实和嫩梢。幼虫蛀食作物生殖器官，导致落花落铃、果实腐烂，严重影响产量和品质。', '棉花：蕾铃被蛀孔，出现黄褐色粪便，铃壳变软腐烂，花蕾脱落，叶片有孔洞或缺刻。
